export const TeacherPortalHtml = "<style>\r\n        :root {\r\n            --primary-blue: #1141b8;\r\n            --secondary-blue: #0b2673;\r\n            --accent-pink: #d81b60;\r\n            --teacher-dark: #0b236e;\r\n            --teacher-darker: #1141b8;\r\n            --bg-light: #eef4ff;\r\n            --text-main: #172033;\r\n            --text-muted: #667085;\r\n            --panel-border: rgba(17,65,184,0.08);\r\n            --sidebar-width: 286px;\r\n            --radius-sm: 12px;\r\n            --radius-md: 16px;\r\n            --radius-lg: 20px;\r\n            --card-shadow: 0 12px 32px rgba(20,36,78,.08);\r\n            --soft-shadow: 0 2px 10px rgba(17,65,184,.05);\r\n        }\r\n\r\n        body {\r\n            background: radial-gradient(circle at top right, rgba(17,65,184,.12), transparent 25%), linear-gradient(180deg,#f8fbff 0%, var(--bg-light) 100%);\r\n            font-family: 'Outfit', sans-serif;\r\n            overflow-x: hidden;\r\n            color: var(--text-main);\r\n        }\r\n\r\n        .sidebar {\r\n            width: var(--sidebar-width);\r\n            height: 100vh;\r\n            background: linear-gradient(180deg, var(--teacher-dark) 0%, var(--teacher-darker) 100%);\r\n            color: #fff;\r\n            position: fixed;\r\n            left: 0;\r\n            top: 0;\r\n            z-index: 1000;\r\n            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\r\n            overflow-y: auto;\r\n            scrollbar-width: thin;\r\n            scrollbar-color: rgba(255,255,255,0.1) transparent;\r\n            display: flex;\r\n            flex-direction: column;\r\n            padding: 18px 14px;\r\n        }\r\n\r\n        .sidebar::-webkit-scrollbar { width: 6px; }\r\n        .sidebar::-webkit-scrollbar-thumb { background-color: rgba(255,255,255,0.1); border-radius: 10px; }\r\n\r\n        .sidebar-header {\r\n            padding: 8px 10px 14px;\r\n            background: transparent;\r\n            border-bottom: 1px solid rgba(255,255,255,.15);\r\n            margin-bottom: 0;\r\n            text-align: left;\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 10px;\r\n        }\r\n\r\n        .sidebar-header h5 {\r\n            color: white;\r\n            letter-spacing: 0;\r\n            font-size: 1rem;\r\n        }\r\n        .sidebar-header .badge {\r\n            background-color: rgba(255,255,255,.14) !important;\r\n            border: 1px solid rgba(255,255,255,.18);\r\n            color: rgba(255,255,255,.78);\r\n            font-weight: 600;\r\n        }\r\n        .sidebar-header img {\r\n            width: 38px;\r\n            height: 38px;\r\n            border-radius: 12px;\r\n            background: rgba(255,255,255,.15);\r\n            padding: 6px;\r\n        }\r\n\r\n        .teacher-chip {\r\n            margin: 12px 8px;\r\n            padding: 12px;\r\n            border-radius: var(--radius-md);\r\n            background: rgba(255,255,255,.12);\r\n            border: 1px solid rgba(255,255,255,.18);\r\n            cursor: pointer;\r\n        }\r\n\r\n        .teacher-chip:hover { background: rgba(255,255,255,.2); }\r\n        .teacher-chip .avatar {\r\n            width: 42px;\r\n            height: 42px;\r\n            border-radius: 12px;\r\n            background: rgba(255,255,255,.2);\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-weight: 800;\r\n            flex-shrink: 0;\r\n        }\r\n\r\n        .nav-menu {\r\n            padding: 0;\r\n            flex-grow: 1;\r\n        }\r\n\r\n        .nav-item {\r\n            list-style: none;\r\n            margin-bottom: 5px;\r\n        }\r\n\r\n        .sidebar .nav-link {\r\n            color: rgba(255,255,255,.88);\r\n            padding: 10px 12px;\r\n            border-radius: 12px;\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 10px;\r\n            transition: all 0.2s;\r\n            text-decoration: none;\r\n            font-weight: 600;\r\n        }\r\n\r\n        .sidebar .nav-link:hover {\r\n            background: rgba(255,255,255,.16);\r\n            color: white;\r\n        }\r\n\r\n        .sidebar .nav-link.active {\r\n            background: rgba(255,255,255,.16);\r\n            color: white;\r\n            font-weight: 600;\r\n            box-shadow: none;\r\n        }\r\n\r\n        .sidebar .nav-link i {\r\n            font-size: 1.08rem;\r\n            transition: all 0.2s;\r\n        }\r\n\r\n        .sidebar .nav-link.active i {\r\n            color: white;\r\n        }\r\n\r\n        .main-wrapper {\r\n            margin-left: var(--sidebar-width);\r\n            min-height: 100vh;\r\n            transition: all 0.3s;\r\n            display: flex;\r\n            flex-direction: column;\r\n        }\r\n\r\n        .top-navbar {\r\n            background: rgba(255,255,255,.9);\r\n            backdrop-filter: blur(14px);\r\n            padding: 14px 22px;\r\n            border-bottom: 1px solid var(--panel-border);\r\n            position: sticky;\r\n            top: 0;\r\n            z-index: 900;\r\n            box-shadow: none;\r\n        }\r\n\r\n        .content-area {\r\n            padding: 22px;\r\n            max-width: 1600px;\r\n            margin: 0 auto;\r\n            width: 100%;\r\n            flex-grow: 1;\r\n        }\r\n\r\n        .dashboard-card {\r\n            background: white;\r\n            border-radius: var(--radius-lg);\r\n            padding: 24px;\r\n            border: 1px solid var(--panel-border);\r\n            box-shadow: var(--card-shadow);\r\n            height: 100%;\r\n            transition: transform .18s ease, box-shadow .18s ease;\r\n        }\r\n\r\n        .stat-card {\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 20px;\r\n        }\r\n\r\n        .stat-icon {\r\n            width: 52px;\r\n            height: 52px;\r\n            border-radius: 14px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-size: 1.8rem;\r\n        }\r\n\r\n        .table-admin th {\r\n            background-color: #f8fbff;\r\n            color: var(--text-muted);\r\n            font-weight: 600;\r\n            text-transform: uppercase;\r\n            font-size: 0.75rem;\r\n            letter-spacing: 1px;\r\n            padding: 15px;\r\n            border-bottom: 1px solid var(--panel-border);\r\n        }\r\n\r\n        .table-admin td {\r\n            padding: 15px;\r\n            vertical-align: middle;\r\n            color: #334155;\r\n            border-bottom: 1px solid rgba(17,65,184,.06);\r\n        }\r\n\r\n        /* Common Elements */\r\n        .view-section {\r\n            display: none;\r\n            transition: all 0.3s ease;\r\n        }\r\n\r\n        .view-section.active {\r\n            display: block;\r\n            animation: fadeIn 0.4s ease-out;\r\n        }\r\n\r\n        @keyframes fadeIn {\r\n            from { opacity: 0; transform: translateY(10px); }\r\n            to { opacity: 1; transform: translateY(0); }\r\n        }\r\n\r\n        /* ===== RESPONSIVE ===== */\r\n        @media (max-width: 991px) {\r\n            .sidebar { left: -100%; z-index: 1050; }\r\n            .sidebar.show { left: 0; }\r\n            .main-wrapper { margin-left: 0 !important; }\r\n            .top-navbar { padding: 12px 16px; }\r\n            .content-area { padding: 16px 12px; }\r\n            .teacher-hero { padding: 18px; }\r\n            .dashboard-card { padding: 18px 14px; }\r\n            .grade-stepper { padding: 12px 14px; flex-wrap: wrap; gap: 8px; }\r\n            .grade-step-connector { display: none; }\r\n            .subject-picker-grid { grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); }\r\n        }\r\n        @media (max-width: 767px) {\r\n            .table-admin th, .table-admin td { padding: 10px 8px; font-size: .8rem; }\r\n            .grade-stats-bar { grid-template-columns: repeat(2, 1fr); }\r\n            .teacher-stat { min-height: unset; padding: 10px; }\r\n            .teacher-stat .metric { font-size: 1.4rem; }\r\n            .top-navbar h4 { font-size: 1rem; }\r\n            .sidebar-header h5 { font-size: .9rem; }\r\n        }\r\n        @media (max-width: 480px) {\r\n            .content-area { padding: 12px 8px; }\r\n            .table-admin th, .table-admin td { padding: 8px 6px; font-size: .75rem; }\r\n            .dashboard-card { padding: 14px 10px; }\r\n            .grade-stat-pill { padding: 10px 8px; }\r\n            .grade-stat-pill .gsnum { font-size: 1.3rem; }\r\n            .subject-picker-grid { grid-template-columns: 1fr 1fr; }\r\n            .subject-picker-card { padding: 10px 12px; }\r\n        }\r\n\r\n        .sidebar-overlay {\r\n            display: none;\r\n            position: fixed;\r\n            top: 0;\r\n            left: 0;\r\n            width: 100vw;\r\n            height: 100vh;\r\n            background: rgba(0,0,0,0.5);\r\n            z-index: 999;\r\n            -webkit-backdrop-filter: blur(2px);\r\n            backdrop-filter: blur(2px);\r\n        }\r\n        .sidebar-overlay.show { display: block; }\r\n\r\n        .bg-primary-subtle {\r\n            background-color: rgba(26, 61, 182, 0.1);\r\n        }\r\n\r\n        .menu-title {\r\n            color: rgba(255,255,255,.6);\r\n            font-size: .72rem;\r\n            text-transform: uppercase;\r\n            letter-spacing: .1em;\r\n            margin: 12px 10px 6px;\r\n            font-weight: 700;\r\n        }\r\n\r\n        .teacher-hero {\r\n            padding: 24px;\r\n            background: linear-gradient(135deg, rgba(17,65,184,.96), rgba(27,99,212,.92));\r\n            color: #fff;\r\n            border: none;\r\n            border-radius: var(--radius-lg);\r\n            box-shadow: var(--card-shadow);\r\n        }\r\n\r\n        .teacher-stat {\r\n            background: rgba(255,255,255,.15);\r\n            border: 1px solid rgba(255,255,255,.14);\r\n            border-radius: var(--radius-md);\r\n            padding: 14px;\r\n            min-height: 96px;\r\n        }\r\n\r\n        .teacher-stat .metric {\r\n            font-size: 1.8rem;\r\n            font-weight: 800;\r\n            line-height: 1;\r\n        }\r\n\r\n        .quick-action-btn {\r\n            width: 100%;\r\n            min-height: 46px;\r\n            border: 1px solid var(--panel-border);\r\n            background: #fff;\r\n            border-radius: var(--radius-sm);\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 12px;\r\n            padding: 10px 12px;\r\n            color: var(--text-main);\r\n            font-weight: 700;\r\n            text-align: left;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n\r\n        .quick-action-btn:hover {\r\n            border-color: rgba(17,65,184,.22);\r\n            background: #f8fbff;\r\n        }\r\n\r\n        .notice-row,\r\n        .session-row-soft {\r\n            background: #fff;\r\n            border: 1px solid var(--panel-border);\r\n            border-radius: var(--radius-sm);\r\n            padding: 12px 14px;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n\r\n        .top-bell {\r\n            width: 42px;\r\n            height: 42px;\r\n            border-radius: 50%;\r\n            border: 1px solid var(--panel-border);\r\n            background: #fff;\r\n            color: var(--primary-blue);\r\n            position: relative;\r\n        }\r\n\r\n        .top-bell .count {\r\n            position: absolute;\r\n            top: -4px;\r\n            right: -4px;\r\n            min-width: 18px;\r\n            height: 18px;\r\n            border-radius: 999px;\r\n            background: #dc2626;\r\n            color: #fff;\r\n            font-size: .68rem;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-weight: 800;\r\n        }\r\n\r\n        .priority-card {\r\n            border: 1px solid var(--panel-border);\r\n            border-radius: var(--radius-md);\r\n            background: #fff;\r\n            padding: 14px;\r\n            min-height: 116px;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n\r\n        .priority-card .icon {\r\n            width: 38px;\r\n            height: 38px;\r\n            border-radius: 12px;\r\n            display: inline-flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            flex-shrink: 0;\r\n        }\r\n\r\n        .subject-summary-card {\r\n            border: 1px solid var(--panel-border);\r\n            border-radius: var(--radius-md);\r\n            background: #fff;\r\n            padding: 16px;\r\n            height: 100%;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n\r\n        .subject-summary-card .meta-line {\r\n            color: var(--text-muted);\r\n            font-size: .82rem;\r\n        }\r\n\r\n        .progress-thin {\r\n            height: 8px;\r\n            border-radius: 999px;\r\n            background: rgba(17,65,184,.1);\r\n            overflow: hidden;\r\n        }\r\n\r\n        .progress-thin > span {\r\n            display: block;\r\n            height: 100%;\r\n            width: 0%;\r\n            background: linear-gradient(90deg,#1141b8,#2c89ff);\r\n        }\r\n\r\n        .flow-step {\r\n            border: 1px solid var(--panel-border);\r\n            border-radius: var(--radius-sm);\r\n            background: #fff;\r\n            padding: 12px;\r\n            height: 100%;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n\r\n        .flow-step .num {\r\n            width: 28px;\r\n            height: 28px;\r\n            border-radius: 50%;\r\n            background: rgba(17,65,184,.1);\r\n            color: var(--primary-blue);\r\n            display: inline-flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-weight: 800;\r\n            font-size: .82rem;\r\n        }\r\n\r\n        .risk-strip {\r\n            border-left: 4px solid #dc2626;\r\n            background: #fff7f7;\r\n        }\r\n\r\n        /* ===== CALIFICACIONES MEJORADO ===== */\r\n        .grade-stepper {\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 0;\r\n            margin-bottom: 24px;\r\n            background: white;\r\n            border-radius: var(--radius-md);\r\n            border: 1px solid var(--panel-border);\r\n            padding: 16px 20px;\r\n            box-shadow: var(--soft-shadow);\r\n            overflow-x: auto;\r\n        }\r\n        .grade-step {\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 10px;\r\n            flex-shrink: 0;\r\n        }\r\n        .grade-step .step-num {\r\n            width: 32px;\r\n            height: 32px;\r\n            border-radius: 50%;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-weight: 800;\r\n            font-size: .85rem;\r\n            border: 2px solid rgba(17,65,184,.2);\r\n            background: rgba(17,65,184,.06);\r\n            color: var(--text-muted);\r\n            transition: all .25s;\r\n        }\r\n        .grade-step.done .step-num {\r\n            background: #dcfce7;\r\n            border-color: #16a34a;\r\n            color: #16a34a;\r\n        }\r\n        .grade-step.active .step-num {\r\n            background: var(--primary-blue);\r\n            border-color: var(--primary-blue);\r\n            color: white;\r\n            box-shadow: 0 0 0 4px rgba(17,65,184,.15);\r\n        }\r\n        .grade-step .step-label { font-weight: 700; font-size: .82rem; color: var(--text-muted); }\r\n        .grade-step.active .step-label { color: var(--primary-blue); }\r\n        .grade-step.done .step-label { color: #16a34a; }\r\n        .grade-step-connector {\r\n            flex: 1;\r\n            min-width: 20px;\r\n            height: 2px;\r\n            background: rgba(17,65,184,.12);\r\n            margin: 0 8px;\r\n        }\r\n        .grade-step-connector.done { background: #16a34a; }\r\n\r\n        .grade-stats-bar {\r\n            display: grid;\r\n            grid-template-columns: repeat(4, 1fr);\r\n            gap: 12px;\r\n            margin-bottom: 20px;\r\n        }\r\n        @media (max-width: 768px) { .grade-stats-bar { grid-template-columns: repeat(2, 1fr); } }\r\n        .grade-stat-pill {\r\n            background: white;\r\n            border: 1px solid var(--panel-border);\r\n            border-radius: var(--radius-md);\r\n            padding: 14px 16px;\r\n            text-align: center;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n        .grade-stat-pill .gsnum {\r\n            font-size: 1.6rem;\r\n            font-weight: 800;\r\n            line-height: 1;\r\n        }\r\n        .grade-stat-pill .gslbl {\r\n            font-size: .72rem;\r\n            font-weight: 700;\r\n            text-transform: uppercase;\r\n            letter-spacing: .06em;\r\n            color: var(--text-muted);\r\n            margin-top: 4px;\r\n        }\r\n\r\n        .grade-progress-wrap {\r\n            background: rgba(17,65,184,.06);\r\n            border-radius: 999px;\r\n            height: 8px;\r\n            overflow: hidden;\r\n            margin-top: 8px;\r\n        }\r\n        .grade-progress-fill {\r\n            height: 100%;\r\n            border-radius: 999px;\r\n            background: linear-gradient(90deg, #1141b8, #2c89ff);\r\n            transition: width .4s ease;\r\n        }\r\n\r\n        .subject-picker-grid {\r\n            display: grid;\r\n            grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));\r\n            gap: 12px;\r\n            margin-bottom: 20px;\r\n        }\r\n        .subject-picker-card {\r\n            border: 2px solid var(--panel-border);\r\n            border-radius: var(--radius-md);\r\n            padding: 14px 16px;\r\n            cursor: pointer;\r\n            transition: all .2s;\r\n            background: white;\r\n            box-shadow: var(--soft-shadow);\r\n        }\r\n        .subject-picker-card:hover { border-color: rgba(17,65,184,.35); background: #f4f8ff; transform: translateY(-2px); }\r\n        .subject-picker-card.selected {\r\n            border-color: var(--primary-blue);\r\n            background: rgba(17,65,184,.06);\r\n            box-shadow: 0 0 0 4px rgba(17,65,184,.1);\r\n        }\r\n        .subject-picker-card .sp-icon {\r\n            width: 38px; height: 38px; border-radius: 10px;\r\n            background: rgba(17,65,184,.1);\r\n            color: var(--primary-blue);\r\n            display: flex; align-items: center; justify-content: center;\r\n            font-size: 1.1rem; margin-bottom: 10px;\r\n        }\r\n        .subject-picker-card.selected .sp-icon { background: var(--primary-blue); color: white; }\r\n        .subject-picker-card .sp-name { font-weight: 700; font-size: .9rem; }\r\n        .subject-picker-card .sp-meta { font-size: .75rem; color: var(--text-muted); margin-top: 3px; }\r\n\r\n        /* Grade input reactivo */\r\n        .grade-input-cell input {\r\n            width: 80px;\r\n            text-align: center;\r\n            font-weight: 800;\r\n            font-size: 1rem;\r\n            border-radius: 10px;\r\n            border: 2px solid var(--panel-border);\r\n            padding: 6px 4px;\r\n            transition: border-color .2s, background .2s;\r\n        }\r\n        .grade-input-cell input:focus { outline: none; border-color: var(--primary-blue); background: rgba(17,65,184,.04); }\r\n        .grade-input-cell input.score-pass { border-color: #16a34a; background: #f0fdf4; color: #15803d; }\r\n        .grade-input-cell input.score-fail { border-color: #dc2626; background: #fef2f2; color: #b91c1c; }\r\n        .grade-input-cell input.score-neutral { border-color: #d97706; background: #fffbeb; color: #92400e; }\r\n    \r\n        /* Estilos Pasaporte Tesis (Industrial) */\r\n        .pp-steps { display: flex; justify-content: space-between; align-items: flex-start; position: relative; padding: 20px 0; min-width: 900px; }\r\n        .pp-steps::before { content: \"\"; position: absolute; top: 38px; left: 0; right: 0; height: 2px; background: rgba(17,65,184,.1); z-index: 0; }\r\n        .pp-step { position: relative; z-index: 1; display: flex; flex-direction: column; align-items: center; width: 80px; }\r\n        .pp-dot { width: 36px; height: 36px; border-radius: 50%; background: #fff; border: 2px solid rgba(17,65,184,.2); display: flex; align-items: center; justify-content: center; margin-bottom: 8px; color: var(--text-muted); transition: all .3s; }\r\n        .pp-step.done .pp-dot { background: var(--primary-blue); border-color: var(--primary-blue); color: #fff; }\r\n        .pp-step.active .pp-dot { background: #fff; border-color: var(--primary-blue); color: var(--primary-blue); box-shadow: 0 0 0 4px rgba(17,65,184,.15); }\r\n        .pp-step-label { font-size: .65rem; font-weight: 700; text-align: center; color: var(--text-muted); line-height: 1.2; }\r\n        .pp-step.done .pp-step-label { color: var(--primary-blue); }\r\n        .pp-step.active .pp-step-label { color: var(--primary-blue); font-weight: 800; }\r\n        .pp-divider { border: 0; border-top: 1px dashed rgba(17,65,184,.15); margin: 15px 0; }\r\n</style>\r\n\r\n    <div class=\"sidebar-overlay\" id=\"sidebarOverlay\" onclick=\"toggleSidebar()\"></div>\r\n\r\n    <!-- Teacher Sidebar -->\r\n    <div class=\"sidebar\" id=\"sidebar\">\r\n        <div class=\"sidebar-header\">\r\n            <img src=\"/assets/images/logo_white.png\" alt=\"MetaEducación\">\r\n            <div>\r\n                <h5 class=\"fw-bold m-0\">MetaEducación</h5>\r\n                <span class=\"badge rounded-pill px-2 mt-1\">Aula Virtual Docente</span>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"teacher-chip\" role=\"button\" tabindex=\"0\" onclick=\"switchView('view-perfil')\" onkeydown=\"if(event.key==='Enter'||event.key===' '){event.preventDefault();switchView('view-perfil');}\">\r\n            <div class=\"d-flex align-items-center gap-2\">\r\n                <div class=\"avatar\" id=\"sideTeacherAvatar\">DO</div>\r\n                <div class=\"min-w-0\">\r\n                    <div class=\"fw-bold text-truncate\" id=\"sideTeacherName\">Cargando...</div>\r\n                    <small class=\"text-white-50\">Expediente docente</small>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        \r\n        <ul class=\"nav-menu mt-3\">\r\n            <li class=\"menu-title\">Principal</li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link active\" data-target=\"view-dashboard\">\r\n                    <i class=\"bi bi-grid-1x2\"></i> Inicio\r\n                </a>\r\n            </li>\r\n            <li class=\"menu-title\">Académico</li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link\" data-target=\"view-materias\">\r\n                    <i class=\"bi bi-journal-bookmark\"></i> Mis Materias\r\n                </a>\r\n            </li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link\" data-target=\"view-calificaciones\">\r\n                    <i class=\"bi bi-check2-square\"></i> Calificaciones\r\n                </a>\r\n            </li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link\" data-target=\"view-tesis\">\r\n                    <i class=\"bi bi-mortarboard-fill\"></i> Dirección de Tesis\r\n                </a>\r\n            </li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link\" data-target=\"view-moodle\">\r\n                    <i class=\"bi bi-laptop\"></i> Moodle Docente\r\n                </a>\r\n            </li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link\" data-target=\"view-asesor\">\r\n                    <i class=\"bi bi-people-fill\"></i> Asesor Virtual\r\n                </a>\r\n            </li>\r\n            <li class=\"menu-title\">Personal</li>\r\n            <li class=\"nav-item\">\r\n                <a href=\"#\" class=\"nav-link\" data-target=\"view-perfil\">\r\n                    <i class=\"bi bi-person-badge\"></i> Mi Perfil\r\n                </a>\r\n            </li>\r\n            <li class=\"nav-item mt-auto pt-4\">\r\n                <a href=\"#\" class=\"nav-link text-danger\" onclick=\"logout()\">\r\n                    <i class=\"bi bi-box-arrow-left\"></i> Cerrar Sesión\r\n                </a>\r\n            </li>\r\n        </ul>\r\n    </div>\r\n\r\n    <!-- Main Wrapper -->\r\n    <div class=\"main-wrapper\">\r\n        <!-- Top Navbar -->\r\n        <nav class=\"top-navbar d-flex justify-content-between align-items-center\">\r\n            <div class=\"d-flex align-items-center gap-3\">\r\n                <button class=\"btn btn-outline-primary rounded-circle d-lg-none\" onclick=\"toggleSidebar()\" title=\"Abrir menú lateral\" aria-label=\"Abrir menú lateral\"><i class=\"bi bi-list\"></i></button>\r\n                <div>\r\n                    <div class=\"small text-secondary fw-semibold\">Campus Docente</div>\r\n                    <h4 class=\"mb-0 fw-bold text-dark\" id=\"topTeacherTitle\">Inicio</h4>\r\n                </div>\r\n            </div>\r\n            \r\n            <div class=\"d-flex align-items-center gap-2 gap-sm-3 flex-wrap justify-content-end\">\r\n                <button class=\"btn btn-primary rounded-pill px-3\" onclick=\"goTeacherToMoodle()\">\r\n                    <i class=\"bi bi-box-arrow-up-right me-2\"></i>Ir a Moodle\r\n                </button>\r\n                <div class=\"dropdown\">\r\n                    <button class=\"top-bell\" data-bs-toggle=\"dropdown\" title=\"Notificaciones\" aria-label=\"Notificaciones\">\r\n                        <i class=\"bi bi-bell-fill\" aria-hidden=\"true\"></i>\r\n                        <span class=\"count\" id=\"teacherNoticeCount\">0</span>\r\n                    </button>\r\n                    <div class=\"dropdown-menu dropdown-menu-end shadow-sm p-2\" style=\"min-width: 330px;\">\r\n                        <div class=\"d-flex justify-content-between align-items-center px-2 pb-2 border-bottom\">\r\n                            <strong>Notificaciones</strong>\r\n                            <button class=\"btn btn-sm btn-outline-primary rounded-pill\" onclick=\"loadTeacherNotifications(true)\">Actualizar</button>\r\n                        </div>\r\n                        <div id=\"teacherNotificationList\" class=\"pt-2\" style=\"max-height: 340px; overflow: auto;\">\r\n                            <div class=\"small text-muted px-2 py-2\">Cargando notificaciones...</div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                \r\n                <div class=\"d-flex align-items-center gap-3\">\r\n                    <div class=\"text-end d-none d-sm-block\">\r\n                        <p class=\"mb-0 fw-bold text-dark\" id=\"teacherName\">Cargando...</p>\r\n                        <span class=\"badge bg-primary-subtle text-primary px-2\" style=\"font-size: 0.7rem;\">DOCENTE</span>\r\n                    </div>\r\n                    <div class=\"avatar-circle bg-primary text-white rounded-circle d-flex align-items-center justify-content-center fw-bold shadow-sm\" style=\"width: 45px; height: 45px; cursor: pointer;\" title=\"Abrir mi perfil\" onclick=\"switchView('view-perfil')\">\r\n                        <i class=\"bi bi-person-badge fs-5\"></i>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </nav>\r\n\r\n        <!-- Content Area -->\r\n        <div class=\"content-area\">\r\n            \r\n            <!-- SECTION: DASHBOARD -->\r\n            <section id=\"view-dashboard\" class=\"view-section active\">\r\n                <section class=\"teacher-hero mb-3\">\r\n                    <div class=\"row g-3 align-items-center\">\r\n                        <div class=\"col-lg-7\">\r\n                            <p class=\"text-white-50 small mb-1 fw-semibold\" style=\"letter-spacing:.04em\">BIENVENIDO DE VUELTA</p>\r\n                            <h1 class=\"h2 fw-bold mb-1\" id=\"teacherHeroName\">Docente</h1>\r\n                            <p class=\"mb-3 text-white-50 small\">Tus materias, calificaciones, Moodle y asesorías en un solo tablero.</p>\r\n                            <div class=\"d-flex gap-2 flex-wrap\">\r\n                                <button class=\"btn btn-light text-primary rounded-pill px-4 fw-semibold\" onclick=\"switchView('view-calificaciones')\">\r\n                                    <i class=\"bi bi-check2-square me-2\"></i>Capturar calificaciones\r\n                                </button>\r\n                                <button class=\"btn btn-outline-light rounded-pill px-4\" onclick=\"goTeacherToMoodle()\">\r\n                                    <i class=\"bi bi-box-arrow-up-right me-2\"></i>Ir a Moodle\r\n                                </button>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-5\">\r\n                            <div class=\"row g-2\">\r\n                                <div class=\"col-6\">\r\n                                    <div class=\"teacher-stat text-center\">\r\n                                        <div class=\"metric\" id=\"teacherSubjectsCount\">0</div>\r\n                                        <div class=\"small text-white-50\">Materias</div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"col-6\">\r\n                                    <div class=\"teacher-stat text-center\">\r\n                                        <div class=\"metric\" id=\"teacherStudentsCount\">0</div>\r\n                                        <div class=\"small text-white-50\">Alumnos</div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"col-6\">\r\n                                    <div class=\"teacher-stat text-center\">\r\n                                        <div class=\"metric\" id=\"teacherDashboardMoodleCount\">0</div>\r\n                                        <div class=\"small text-white-50\">Cursos Moodle</div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"col-6\">\r\n                                    <div class=\"teacher-stat text-center\">\r\n                                        <div class=\"metric\">2026-1</div>\r\n                                        <div class=\"small text-white-50\">Periodo</div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </section>\r\n\r\n                <div class=\"dashboard-card mb-3\">\r\n                    <div class=\"d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2\">\r\n                        <div>\r\n                            <h2 class=\"h5 fw-bold mb-0\">Prioridad hoy</h2>\r\n                            <p class=\"text-muted small mb-0\">Tareas ordenadas por impacto académico</p>\r\n                        </div>\r\n                        <span class=\"badge rounded-pill text-primary\" style=\"background: rgba(17,65,184,.08);\" id=\"teacherWorkQueueCount\">0 pendientes</span>\r\n                    </div>\r\n                    <div class=\"row g-3\" id=\"teacherWorkQueue\">\r\n                        <div class=\"col-12\"><div class=\"notice-row text-muted small\">Cargando prioridades...</div></div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"dashboard-card mb-3\">\r\n                    <div class=\"d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2\">\r\n                        <div>\r\n                            <h2 class=\"h5 fw-bold mb-0\">Mapa de materias</h2>\r\n                            <p class=\"text-muted small mb-0\">Resumen rápido por grupo para decidir dónde trabajar</p>\r\n                        </div>\r\n                        <button class=\"btn btn-sm btn-outline-primary rounded-pill px-3\" onclick=\"switchView('view-materias')\">\r\n                            Ver detalle <i class=\"bi bi-arrow-right ms-1\"></i>\r\n                        </button>\r\n                    </div>\r\n                    <div class=\"row g-3\" id=\"teacherSubjectMap\">\r\n                        <div class=\"col-12\"><div class=\"notice-row text-muted small\">Cargando materias...</div></div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"row g-3\">\r\n                    <div class=\"col-lg-8\">\r\n                        <div class=\"dashboard-card h-100\">\r\n                            <div class=\"d-flex justify-content-between align-items-center mb-3\">\r\n                                <div>\r\n                                    <h2 class=\"h5 fw-bold mb-0\">Avisos Recientes</h2>\r\n                                    <p class=\"text-muted small mb-0\">Alertas academicas y seguimiento pendiente</p>\r\n                                </div>\r\n                                <button class=\"btn btn-sm btn-outline-primary rounded-pill px-3\" onclick=\"loadTeacherNotifications(true)\">\r\n                                    Actualizar <i class=\"bi bi-arrow-repeat ms-1\"></i>\r\n                                </button>\r\n                            </div>\r\n                            <div id=\"teacherDashNotices\" class=\"vstack gap-2\">\r\n                                <div class=\"notice-row text-muted small\">Cargando notificaciones...</div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-lg-4\">\r\n                        <div class=\"dashboard-card h-100\">\r\n                            <h2 class=\"h5 fw-bold mb-3\">Accesos rápidos</h2>\r\n                            <div class=\"vstack gap-2\">\r\n                                <button class=\"btn quick-action-btn\" onclick=\"switchView('view-materias')\">\r\n                                    <i class=\"bi bi-journal-bookmark-fill text-primary\"></i>\r\n                                    <span>Mis Materias</span>\r\n                                    <i class=\"bi bi-chevron-right ms-auto text-secondary\"></i>\r\n                                </button>\r\n                                <button class=\"btn quick-action-btn\" onclick=\"switchView('view-calificaciones')\">\r\n                                    <i class=\"bi bi-check2-square text-danger\"></i>\r\n                                    <span>Calificaciones</span>\r\n                                    <i class=\"bi bi-chevron-right ms-auto text-secondary\"></i>\r\n                                </button>\r\n                                <button class=\"btn quick-action-btn\" onclick=\"switchView('view-moodle')\">\r\n                                    <i class=\"bi bi-laptop text-info\"></i>\r\n                                    <span>Moodle Docente</span>\r\n                                    <i class=\"bi bi-chevron-right ms-auto text-secondary\"></i>\r\n                                </button>\r\n                                <button class=\"btn quick-action-btn\" onclick=\"switchView('view-asesor')\">\r\n                                    <i class=\"bi bi-people-fill text-success\"></i>\r\n                                    <span>Asesor Virtual</span>\r\n                                    <i class=\"bi bi-chevron-right ms-auto text-secondary\"></i>\r\n                                </button>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n\r\n            <!-- SECTION: CALIFICACIONES -->\r\n            <section id=\"view-calificaciones\" class=\"view-section\">\r\n                <div class=\"d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2\">\r\n                    <div>\r\n                        <h2 class=\"fw-bold mb-0\">Captura de Calificaciones</h2>\r\n                        <p class=\"text-muted small mb-0\">Selecciona una materia, registra notas, adjunta comprobantes e imprime el acta.</p>\r\n                    </div>\r\n                    <div class=\"d-flex gap-2 flex-wrap\">\r\n                        <button type=\"button\" id=\"btnSaveAll\" class=\"btn btn-success rounded-pill\" onclick=\"saveAllGrades()\" style=\"display:none\">\r\n                            <i class=\"bi bi-floppy-fill me-2\"></i>Guardar Todo\r\n                        </button>\r\n                        <button type=\"button\" id=\"btnPrintFormat\" class=\"btn btn-outline-secondary rounded-pill\" onclick=\"printGradeFormat()\" style=\"display:none\">\r\n                            <i class=\"bi bi-printer-fill me-2\"></i>Imprimir Acta\r\n                        </button>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Stepper visual -->\r\n                <div class=\"grade-stepper\" id=\"gradeStepper\">\r\n                    <div class=\"grade-step active\" id=\"gstep1\">\r\n                        <div class=\"step-num\">1</div>\r\n                        <div class=\"step-label\">Materia</div>\r\n                    </div>\r\n                    <div class=\"grade-step-connector\" id=\"gconn1\"></div>\r\n                    <div class=\"grade-step\" id=\"gstep2\">\r\n                        <div class=\"step-num\">2</div>\r\n                        <div class=\"step-label\">Captura</div>\r\n                    </div>\r\n                    <div class=\"grade-step-connector\" id=\"gconn2\"></div>\r\n                    <div class=\"grade-step\" id=\"gstep3\">\r\n                        <div class=\"step-num\">3</div>\r\n                        <div class=\"step-label\">Comprobantes</div>\r\n                    </div>\r\n                    <div class=\"grade-step-connector\" id=\"gconn3\"></div>\r\n                    <div class=\"grade-step\" id=\"gstep4\">\r\n                        <div class=\"step-num\">4</div>\r\n                        <div class=\"step-label\">Cierre</div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Selector de materia como cards -->\r\n                <div id=\"subjectPickerPanel\">\r\n                    <p class=\"fw-semibold mb-2 text-muted small\"><i class=\"bi bi-hand-index me-1\"></i>ELIGE UNA MATERIA PARA COMENZAR</p>\r\n                    <div class=\"subject-picker-grid\" id=\"subjectPickerGrid\">\r\n                        <div class=\"notice-row text-muted small\">Cargando materias...</div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Select oculto para compatibilidad con JS existente -->\r\n                <select id=\"selectSubjectForGrades\" style=\"display:none\" onchange=\"loadStudentsForSubject()\"></select>\r\n\r\n                <!-- Panel de estadísticas (oculto hasta seleccionar materia) -->\r\n                <div id=\"gradeStatsPanel\" style=\"display:none\">\r\n                    <div class=\"grade-stats-bar\">\r\n                        <div class=\"grade-stat-pill\">\r\n                            <div class=\"gsnum text-primary\" id=\"gsTotal\">0</div>\r\n                            <div class=\"gslbl\">Alumnos</div>\r\n                        </div>\r\n                        <div class=\"grade-stat-pill\">\r\n                            <div class=\"gsnum text-success\" id=\"gsCaptured\">0</div>\r\n                            <div class=\"gslbl\">Capturados</div>\r\n                            <div class=\"grade-progress-wrap mt-2\"><div class=\"grade-progress-fill\" id=\"gsProgressBar\" style=\"width:0%\"></div></div>\r\n                        </div>\r\n                        <div class=\"grade-stat-pill\">\r\n                            <div class=\"gsnum text-danger\" id=\"gsPending\">0</div>\r\n                            <div class=\"gslbl\">Pendientes</div>\r\n                        </div>\r\n                        <div class=\"grade-stat-pill\">\r\n                            <div class=\"gsnum text-warning\" id=\"gsNoDocs\">0</div>\r\n                            <div class=\"gslbl\">Sin Comprobante</div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Área de captura -->\r\n                <div class=\"dashboard-card\" id=\"gradingArea\" style=\"display:none\">\r\n                    <div class=\"d-flex align-items-center justify-content-between mb-3 flex-wrap gap-2\">\r\n                        <div class=\"d-flex align-items-center gap-2\">\r\n                            <button class=\"btn btn-sm btn-outline-secondary rounded-pill\" onclick=\"resetSubjectPicker()\">\r\n                                <i class=\"bi bi-arrow-left me-1\"></i>Cambiar materia\r\n                            </button>\r\n                            <span class=\"fw-bold\" id=\"gradeSubjectTitle\"></span>\r\n                        </div>\r\n                        <span class=\"text-muted small\" id=\"gradeSubjectMeta\"></span>\r\n                    </div>\r\n\r\n                    <!-- Leyenda -->\r\n                    <div class=\"d-flex gap-3 mb-3 flex-wrap align-items-center\">\r\n                        <span class=\"small text-muted\"><i class=\"bi bi-info-circle me-1\"></i>Ingresa la nota (0–10) y haz clic en <strong>Guardar</strong> o usa <strong>Guardar Todo</strong>.</span>\r\n                        <span class=\"small\"><span class=\"badge bg-success-subtle text-success border border-success-subtle me-1\"><i class=\"bi bi-check-circle-fill\"></i></span>Comprobante subido</span>\r\n                        <span class=\"small\"><span class=\"badge bg-light text-secondary border me-1\"><i class=\"bi bi-camera\"></i></span>Sin comprobante</span>\r\n                    </div>\r\n\r\n                    <!-- Tabs de grupo -->\r\n                    <div id=\"gradingGroupTabs\" class=\"d-flex gap-2 mb-3 flex-wrap\"></div>\r\n\r\n                    <div class=\"table-responsive\">\r\n                        <table class=\"table table-admin\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th style=\"width:100px\">Matrícula</th>\r\n                                    <th>Nombre del Alumno</th>\r\n                                    <th style=\"width:100px\">Calificación</th>\r\n                                    <th style=\"width:90px\">Estatus</th>\r\n                                    <th>Comprobante</th>\r\n                                    <th style=\"width:130px\">Acción</th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody id=\"gradingTableBody\"></tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Placeholder vacío -->\r\n                <div id=\"gradingPlaceholder\" class=\"dashboard-card text-center py-5\">\r\n                    <div style=\"font-size:3.5rem;margin-bottom:12px;\">📋</div>\r\n                    <h5 class=\"fw-bold mb-1\">Selecciona una materia arriba</h5>\r\n                    <p class=\"text-muted small mb-0\">Verás el listado de alumnos, sus calificaciones y el estado de comprobantes.</p>\r\n                </div>\r\n            </section>\r\n\r\n            <!-- SECTION: MATERIAS -->\r\n            <section id=\"view-materias\" class=\"view-section\">\r\n                <div class=\"d-flex justify-content-between align-items-center mb-4\">\r\n                    <h2 class=\"fw-bold mb-0\">Mis Materias</h2>\r\n                </div>\r\n                <div class=\"row g-3 mb-3\" id=\"teacherSubjectsSummary\">\r\n                    <div class=\"col-12\"><div class=\"notice-row text-muted small\">Cargando resumen académico...</div></div>\r\n                </div>\r\n                <div class=\"dashboard-card\">\r\n                    <div class=\"table-responsive\">\r\n                        <table class=\"table table-admin\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th>ID</th>\r\n                                    <th>Nombre de la Materia</th>\r\n                                    <th>Carrera</th>\r\n                                    <th>Semestre</th>\r\n                                    <th>Créditos</th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody id=\"teacherSubjectsTableBody\">\r\n                                <tr><td colspan=\"5\" class=\"text-center py-4 text-muted\">Cargando materias...</td></tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n\r\n            <!-- SECTION: MOODLE DOCENTE -->\r\n            <section id=\"view-moodle\" class=\"view-section\">\r\n                <div class=\"d-flex justify-content-between align-items-center mb-4 flex-wrap gap-2\">\r\n                    <h2 class=\"fw-bold mb-0\">Moodle Docente</h2>\r\n                    <button class=\"btn btn-outline-primary rounded-pill\" onclick=\"loadTeacherMoodleData()\">\r\n                        <i class=\"bi bi-arrow-clockwise me-2\"></i>Actualizar\r\n                    </button>\r\n                </div>\r\n                <div class=\"row g-4 mb-4\">\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"dashboard-card stat-card\">\r\n                            <div class=\"stat-icon bg-primary bg-opacity-10 text-primary\">\r\n                                <i class=\"bi bi-journal-bookmark-fill\"></i>\r\n                            </div>\r\n                            <div>\r\n                                <p class=\"text-muted small fw-bold mb-1\">Cursos Moodle</p>\r\n                                <h3 class=\"fw-800 mb-0\" id=\"teacherMoodleCourseCount\">0</h3>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"dashboard-card stat-card\">\r\n                            <div class=\"stat-icon bg-success bg-opacity-10 text-success\">\r\n                                <i class=\"bi bi-link-45deg\"></i>\r\n                            </div>\r\n                            <div>\r\n                                <p class=\"text-muted small fw-bold mb-1\">Vínculos activos</p>\r\n                                <h3 class=\"fw-800 mb-0\" id=\"teacherMoodleLinkedCount\">0</h3>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"dashboard-card stat-card\">\r\n                            <div class=\"stat-icon bg-info bg-opacity-10 text-info\">\r\n                                <i class=\"bi bi-people-fill\"></i>\r\n                            </div>\r\n                            <div>\r\n                                <p class=\"text-muted small fw-bold mb-1\">Participantes</p>\r\n                                <h3 class=\"fw-800 mb-0\" id=\"teacherMoodleParticipantsCount\">0</h3>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"dashboard-card mb-4\">\r\n                    <div class=\"table-responsive\">\r\n                        <table class=\"table table-admin\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th>Curso</th>\r\n                                    <th>Materia</th>\r\n                                    <th>Semestre</th>\r\n                                    <th>Participantes</th>\r\n                                    <th>Acción</th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody id=\"teacherMoodleCoursesTableBody\">\r\n                                <tr><td colspan=\"5\" class=\"text-center py-4 text-muted\">Cargando cursos Moodle...</td></tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row g-4\">\r\n                    <div class=\"col-lg-6\">\r\n                        <div class=\"dashboard-card h-100\">\r\n                            <h5 class=\"fw-bold mb-3\">Contenido del Curso</h5>\r\n                            <p class=\"small text-muted mb-2\" id=\"teacherMoodleCourseInfo\">Selecciona un curso para ver sus módulos.</p>\r\n                            <div id=\"teacherMoodleContents\" class=\"vstack gap-2\">\r\n                                <div class=\"text-muted small\">Sin datos por ahora.</div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-lg-6\">\r\n                        <div class=\"dashboard-card h-100\">\r\n                            <h5 class=\"fw-bold mb-3\">Participantes en Moodle</h5>\r\n                            <div id=\"teacherMoodleParticipants\" class=\"vstack gap-2\">\r\n                                <div class=\"text-muted small\">Sin datos por ahora.</div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n\r\n            <section id=\"view-asesor\" class=\"view-section\">\r\n                <div class=\"d-flex justify-content-between align-items-center mb-4 flex-wrap gap-2\">\r\n                    <div>\r\n                        <h2 class=\"fw-bold mb-0\">Asesor Académico</h2>\r\n                        <p class=\"text-muted small mb-0\">Gestiona asesorías, sesiones y mensajes con tus alumnos asignados.</p>\r\n                    </div>\r\n                    <button type=\"button\" class=\"btn btn-outline-primary rounded-pill\" onclick=\"loadTeacherAdvisorData(true)\">\r\n                        <i class=\"bi bi-arrow-repeat me-2\"></i>Actualizar\r\n                    </button>\r\n                </div>\r\n\r\n                <!-- Alumnos -->\r\n                <div class=\"dashboard-card mb-4\">\r\n                    <h5 class=\"fw-bold mb-3\"><i class=\"bi bi-people-fill me-2 text-primary\"></i>Mis Alumnos Asignados</h5>\r\n                    <div id=\"teacherAdvisorStudentsBody\" class=\"row g-3\">\r\n                        <div class=\"col-12 text-center text-muted py-4\">Cargando alumnos...</div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Acciones -->\r\n                <div class=\"row g-4\">\r\n                    <!-- Mensaje -->\r\n                    <div class=\"col-lg-6\">\r\n                        <div class=\"dashboard-card h-100\">\r\n                            <h5 class=\"fw-bold mb-3\"><i class=\"bi bi-chat-dots-fill me-2 text-primary\"></i>Enviar Mensaje</h5>\r\n                            <form id=\"teacherAdvisorMessageForm\" class=\"vstack gap-3\">\r\n                                <div>\r\n                                    <label class=\"form-label text-muted small\">Alumno</label>\r\n                                    <select class=\"form-select\" id=\"advisorMessageStudent\" required>\r\n                                        <option value=\"\">Selecciona alumno...</option>\r\n                                    </select>\r\n                                </div>\r\n                                <div>\r\n                                    <label class=\"form-label text-muted small\">Asunto</label>\r\n                                    <input type=\"text\" class=\"form-control\" id=\"advisorMessageTitle\" maxlength=\"180\" required placeholder=\"Ej. Seguimiento de materias en riesgo\">\r\n                                </div>\r\n                                <div>\r\n                                    <label class=\"form-label text-muted small\">Mensaje</label>\r\n                                    <textarea class=\"form-control\" id=\"advisorMessageBody\" rows=\"3\" required placeholder=\"Escribe tu orientación para el alumno\"></textarea>\r\n                                </div>\r\n                                <button type=\"submit\" class=\"btn btn-primary rounded-pill\">Enviar Mensaje</button>\r\n                            </form>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <!-- Agendar sesión -->\r\n                    <div class=\"col-lg-6\">\r\n                        <div class=\"dashboard-card h-100\">\r\n                            <h5 class=\"fw-bold mb-3\"><i class=\"bi bi-calendar-plus-fill me-2 text-success\"></i>Agendar Asesoría</h5>\r\n                            <form id=\"teacherAdvisorSessionForm\" class=\"vstack gap-3\">\r\n                                <div>\r\n                                    <label class=\"form-label text-muted small\">Alumno</label>\r\n                                    <select class=\"form-select\" id=\"sessionStudent\" required>\r\n                                        <option value=\"\">Selecciona alumno...</option>\r\n                                    </select>\r\n                                </div>\r\n                                <div class=\"row g-2\">\r\n                                    <div class=\"col-7\">\r\n                                        <label class=\"form-label text-muted small\">Fecha y hora</label>\r\n                                        <input type=\"datetime-local\" class=\"form-control\" id=\"sessionDate\" required>\r\n                                    </div>\r\n                                    <div class=\"col-5\">\r\n                                        <label class=\"form-label text-muted small\">Duración</label>\r\n                                        <select class=\"form-select\" id=\"sessionDuration\">\r\n                                            <option value=\"15\">15 min</option>\r\n                                            <option value=\"30\" selected>30 min</option>\r\n                                            <option value=\"45\">45 min</option>\r\n                                            <option value=\"60\">1 hora</option>\r\n                                        </select>\r\n                                    </div>\r\n                                </div>\r\n                                <div>\r\n                                    <label class=\"form-label text-muted small\">Tema de la asesoría</label>\r\n                                    <input type=\"text\" class=\"form-control\" id=\"sessionTopic\" maxlength=\"200\" required placeholder=\"Ej. Revisión de materias en riesgo\">\r\n                                </div>\r\n                                <div>\r\n                                    <label class=\"form-label text-muted small\">Notas adicionales</label>\r\n                                    <textarea class=\"form-control\" id=\"sessionNotes\" rows=\"2\" placeholder=\"Opcional: indicaciones previas, enlace de videollamada...\"></textarea>\r\n                                </div>\r\n                                <button type=\"submit\" class=\"btn btn-success rounded-pill\">Agendar Sesión</button>\r\n                            </form>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- Sesiones agendadas -->\r\n                <div class=\"dashboard-card mt-4\">\r\n                    <div class=\"d-flex justify-content-between align-items-center mb-3\">\r\n                        <h5 class=\"fw-bold mb-0\"><i class=\"bi bi-calendar-check-fill me-2 text-success\"></i>Sesiones Agendadas</h5>\r\n                        <span class=\"badge bg-light text-dark border\" id=\"sessionCountBadge\">-</span>\r\n                    </div>\r\n                    <div id=\"teacherSessionsList\"><div class=\"text-center text-muted py-3\">Cargando sesiones...</div></div>\r\n                </div>\r\n            </section>\r\n\r\n            <!-- SECTION: MI PERFIL -->\r\n            \r\n            <section id=\"view-tesis\" class=\"view-section\">\r\n                <div class=\"d-flex justify-content-between align-items-center mb-4 flex-wrap gap-2\">\r\n                    <div>\r\n                        <h2 class=\"fw-bold mb-0\">Dirección de Tesis</h2>\r\n                        <p class=\"text-muted small mb-0\">Supervisa y autoriza el progreso de los alumnos que diriges.</p>\r\n                    </div>\r\n                    <div class=\"d-flex gap-2\">\r\n                        <a href=\"/proceso-academico\" class=\"btn btn-outline-primary rounded-pill px-3\">\r\n                            <i class=\"bi bi-bar-chart-line me-2\"></i>Ver Métricas Estándar\r\n                        </a>\r\n                        <button type=\"button\" class=\"btn btn-primary rounded-pill\" onclick=\"loadTeacherThesisStudents(true)\">\r\n                            <i class=\"bi bi-arrow-repeat me-2\"></i>Actualizar\r\n                        </button>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"dashboard-card mb-4\">\r\n                    <h5 class=\"fw-bold mb-3\"><i class=\"bi bi-mortarboard-fill me-2 text-primary\"></i>Alumnos en Dirección de Tesis</h5>\r\n                    <div id=\"teacherThesisStudentsBody\" class=\"row g-3\">\r\n                        <div class=\"col-12 text-center text-muted py-4\">Cargando alumnos...</div>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n<section id=\"view-perfil\" class=\"view-section\">\r\n                <div class=\"d-flex justify-content-between align-items-center mb-4\">\r\n                    <h2 class=\"fw-bold mb-0\">Mi Perfil</h2>\r\n                    <button class=\"btn btn-primary rounded-pill\" onclick=\"saveProfile()\"><i class=\"bi bi-save me-2\"></i>Guardar Cambios</button>\r\n                </div>\r\n                <div class=\"dashboard-card\">\r\n                    <div class=\"row\">\r\n                        <div class=\"col-md-4 text-center border-end\">\r\n                            <div class=\"bg-primary text-white rounded-circle d-inline-flex align-items-center justify-content-center mb-3 shadow\" style=\"width: 120px; height: 120px; font-size: 3rem;\" id=\"profileInitials\"></div>\r\n                            <h4 class=\"fw-bold mb-1\" id=\"profileNameDisplay\"></h4>\r\n                            <p class=\"text-muted mb-3\" id=\"profileUsernameDisplay\"></p>\r\n                        </div>\r\n                        <div class=\"col-md-8 px-4\">\r\n                            <form id=\"profileForm\">\r\n                                <h5 class=\"fw-bold mb-3 border-bottom pb-2\">Datos Personales</h5>\r\n                                <div class=\"mb-3\">\r\n                                    <label class=\"form-label text-muted small\">Nombre Completo</label>\r\n                                    <input type=\"text\" class=\"form-control\" id=\"profileName\" required>\r\n                                </div>\r\n                                <div class=\"mb-3\">\r\n                                    <label class=\"form-label text-muted small\">Correo Electrónico</label>\r\n                                    <input type=\"email\" class=\"form-control\" id=\"profileEmail\" required>\r\n                                </div>\r\n                                \r\n                                <h5 class=\"fw-bold mb-3 mt-4 border-bottom pb-2\">Seguridad</h5>\r\n                                <div class=\"mb-3\">\r\n                                    <label class=\"form-label text-muted small\">Nueva Contraseña (dejar en blanco para no cambiar)</label>\r\n                                    <input type=\"password\" class=\"form-control\" id=\"profilePassword\">\r\n                                </div>\r\n                            </form>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n        </div>\r\n    </div>\r\n\r\n    <!-- TOAST NOTIFICATIONS -->\r\n    <div class=\"toast-container position-fixed bottom-0 end-0 p-3\" style=\"z-index: 1060;\">\r\n        <div id=\"teacherToast\" class=\"toast align-items-center text-white bg-success border-0 rounded-3\" role=\"alert\">\r\n            <div class=\"d-flex\">\r\n                <div class=\"toast-body\" id=\"teacherToastMessage\">Acción realizada con éxito.</div>\r\n                <button type=\"button\" class=\"btn-close btn-close-white me-2 m-auto\" data-bs-dismiss=\"toast\" title=\"Cerrar notificación\" aria-label=\"Cerrar notificación\"></button>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js\"></script>\r\n    <script src=\"/assets/js/api.js\"></script>\r\n    <script>\r\n        let currentTeacher = null;\r\n        let allSubjects = [];\r\n        let allStudents = [];\r\n        let teacherMoodleCourses = [];\r\n        let teacherNotifications = [];\r\n        let teacherAdvisorStudents = [];\r\n        let teacherAdvisorSessions = [];\r\n        let teacherThesisStudents = [];\r\n        const THESIS_STEPS = [\r\n            {key:'Sin Iniciar',    label:'Sin Iniciar',       icon:'bi-hourglass',               cuatri:'—',  kpi:'Registro inicial'},\r\n            {key:'Perfil',         label:'Perfil\\nProyecto',  icon:'bi-lightbulb-fill',           cuatri:'3°', kpi:'Problema < 300 pal.'},\r\n            {key:'Protocolo',      label:'Protocolo',         icon:'bi-file-earmark-text-fill',   cuatri:'4°', kpi:'Gantt 100% tareas'},\r\n            {key:'Marco Teorico',  label:'Marco\\nTeórico',    icon:'bi-book-fill',                cuatri:'5°', kpi:'25 fuentes APA 7'},\r\n            {key:'Diseño',         label:'Diseño\\nSistema',   icon:'bi-diagram-3-fill',           cuatri:'6°', kpi:'UML + Normaliz.'},\r\n            {key:'Implementacion', label:'Implementación',    icon:'bi-gear-wide-connected',      cuatri:'7°', kpi:'Git + 80% Cobert.'},\r\n            {key:'Pruebas',        label:'Pruebas\\nValidac.', icon:'bi-clipboard2-check-fill',    cuatri:'8°a',kpi:'100% Req. Func.'},\r\n            {key:'Redaccion',      label:'Redacción\\nFinal',  icon:'bi-pencil-fill',              cuatri:'8°b',kpi:'Turnitin < 15%'},\r\n            {key:'Revisiones',     label:'Revisiones\\nComité',icon:'bi-eye-fill',                 cuatri:'9°a',kpi:'Respuesta < 72h'},\r\n            {key:'Defensa',        label:'Examen\\nProfesional',icon:'bi-mic-fill',                cuatri:'9°b',kpi:'20 min / 10 slides'},\r\n            {key:'Titulado',       label:'Titulado',          icon:'bi-award-fill',               cuatri:'✓',  kpi:'Cierre Proceso'},\r\n        ];\r\n\r\n        function renderThesisSteps(currentStatus) {\r\n            const currentIdx = THESIS_STEPS.findIndex(s => s.key === currentStatus);\r\n            return THESIS_STEPS.map((s, idx) => {\r\n                const isDone = idx < currentIdx;\r\n                const isActive = idx === currentIdx;\r\n                const cls = isDone ? 'done' : isActive ? 'active' : '';\r\n                const ic = isDone ? 'bi-check-lg' : s.icon;\r\n                const cuatriBadge = s.cuatri && s.cuatri !== '—' ? `<span class=\"badge bg-primary-subtle text-primary border border-primary-subtle rounded-pill position-absolute top-0 start-50 translate-middle-x\" style=\"font-size:0.45rem; z-index:2; padding: 2px 5px; margin-top:-10px;\">${s.cuatri}</span>` : '';\r\n                return `<div class=\"pp-step ${cls}\" title=\"KPI: ${s.kpi}\" style=\"position:relative;\">\r\n                    ${cuatriBadge}\r\n                    <div class=\"pp-dot\"><i class=\"bi ${ic}\"></i></div>\r\n                    <div class=\"pp-step-label\">${s.label.replace('\\n', '<br>')}</div>\r\n                    <div class=\"small fw-bold text-muted mt-1\" style=\"font-size:0.5rem; opacity:0.8;\">KPI: ${s.kpi || \"\"}</div>\r\n                </div>`;\r\n            }).join('');\r\n        }\r\n\r\n        async function loadTeacherThesisStudents(showToastOnSuccess = false) {\r\n            const token = localStorage.getItem('token');\r\n            const el = document.getElementById('teacherThesisStudentsBody');\r\n            if (!el) return;\r\n            el.innerHTML = '<div class=\"col-12 text-center text-muted py-4\">Cargando alumnos de tesis...</div>';\r\n\r\n            try {\r\n                // Por ahora usamos el mismo endpoint de asesoría pero podríamos tener uno específico\r\n                const res = await fetch('http://localhost:8000/teacher/advisor/students', { \r\n                    headers: { 'Authorization': `Bearer ${token}` } \r\n                });\r\n                if (!res.ok) throw new Error('Error al cargar tesis');\r\n                const data = await res.json();\r\n                teacherThesisStudents = (data.students || []).filter(s => s.source === 'direct' || s.carrera); // Filtro simple\r\n\r\n                el.innerHTML = teacherThesisStudents.length ? teacherThesisStudents.map(s => {\r\n                    const thesis = s.pasaporte?.thesis || {};\r\n                    const curStatus = thesis.status || 'Sin Iniciar';\r\n                    return `\r\n                    <div class=\"col-12\">\r\n                        <div class=\"dashboard-card mb-3\">\r\n                            <div class=\"d-flex align-items-center gap-3 mb-3 flex-wrap\">\r\n                                <div class=\"avatar-circle bg-primary text-white rounded-circle d-flex align-items-center justify-content-center fw-bold\" style=\"width:48px;height:48px\">\r\n                                    ${(s.full_name||s.username).charAt(0)}\r\n                                </div>\r\n                                <div class=\"flex-grow-1\">\r\n                                    <div class=\"fw-bold fs-5\">${s.full_name || s.username}</div>\r\n                                    <div class=\"small text-muted\">${s.username} · ${s.carrera || 'Sin carrera'}</div>\r\n                                </div>\r\n                                <div class=\"text-end\">\r\n                                    <div class=\"small text-muted mb-1\">Estatus Actual</div>\r\n                                    <select class=\"form-select form-select-sm rounded-pill fw-bold\" \r\n                                            onchange=\"updateStudentThesisStatus('${s.username}', this.value)\"\r\n                                            style=\"width:200px; border-color:var(--primary-blue)\">\r\n                                        ${THESIS_STEPS.map(opt => `<option value=\"${opt.key}\" ${opt.key === curStatus ? 'selected' : ''}>${opt.label.replace('\\n', ' ')}</option>`).join('')}\r\n                                    </select>\r\n                                </div>\r\n                            </div>\r\n                            \r\n                            <div class=\"pp-divider mb-4\"></div>\r\n                            \r\n                            <div class=\"pp-steps-container\" style=\"overflow-x:auto; padding-bottom:10px;\">\r\n                                <div class=\"pp-steps d-flex justify-content-between\">\r\n                                    ${renderThesisSteps(curStatus)}\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </div>`;\r\n                }).join('') : '<div class=\"col-12 text-center text-muted py-4\">No tienes alumnos asignados para dirección de tesis.</div>';\r\n\r\n                if (showToastOnSuccess) showToast('Lista de tesis actualizada');\r\n            } catch (error) {\r\n                console.error(error);\r\n                el.innerHTML = '<div class=\"col-12 text-center text-danger py-4\">Error al cargar datos de tesis.</div>';\r\n            }\r\n        }\r\n\r\n        async function updateStudentThesisStatus(username, newStatus) {\r\n            const token = localStorage.getItem('token');\r\n            try {\r\n                const res = await fetch(`http://localhost:8000/teacher/advisor/students/${encodeURIComponent(username)}/thesis-status`, {\r\n                    method: 'PUT',\r\n                    headers: {\r\n                        'Authorization': `Bearer ${token}`,\r\n                        'Content-Type': 'application/json'\r\n                    },\r\n                    body: JSON.stringify({ status: newStatus })\r\n                });\r\n\r\n                if (!res.ok) {\r\n                    const err = await res.json().catch(() => ({}));\r\n                    throw new Error(err.detail || 'Error al actualizar estatus');\r\n                }\r\n                showToast(`Estatus de ${username} actualizado a ${newStatus}`);\r\n                loadTeacherThesisStudents(false);\r\n            } catch (error) {\r\n                console.error(error);\r\n                showToast(error.message || 'Error al guardar cambio de estatus', 'danger');\r\n            }\r\n        }\r\n\r\n\r\n        function showToast(message, type = 'success') {\r\n            const toastEl = document.getElementById('teacherToast');\r\n            const toastMessage = document.getElementById('teacherToastMessage');\r\n            \r\n            toastEl.className = `toast align-items-center text-white bg-${type} border-0 rounded-3`;\r\n            toastMessage.textContent = message;\r\n            \r\n            const toast = new bootstrap.Toast(toastEl);\r\n            toast.show();\r\n        }\r\n\r\n        function fixMojibakeString(input) {\r\n            if (typeof input !== 'string' || !input) return input;\r\n            if (!/[ÃÂâ]/.test(input)) return input;\r\n            try {\r\n                return decodeURIComponent(escape(input));\r\n            } catch (_) {\r\n                return input;\r\n            }\r\n        }\r\n\r\n        function fixMojibakeInDom(root = document.body) {\r\n            if (!root) return;\r\n            const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT);\r\n            const textNodes = [];\r\n            while (walker.nextNode()) textNodes.push(walker.currentNode);\r\n            textNodes.forEach((node) => {\r\n                const fixed = fixMojibakeString(node.nodeValue);\r\n                if (fixed !== node.nodeValue) node.nodeValue = fixed;\r\n            });\r\n            root.querySelectorAll('[title], [placeholder], [aria-label]').forEach((el) => {\r\n                ['title', 'placeholder', 'aria-label'].forEach((attr) => {\r\n                    const value = el.getAttribute(attr);\r\n                    if (!value) return;\r\n                    const fixed = fixMojibakeString(value);\r\n                    if (fixed !== value) el.setAttribute(attr, fixed);\r\n                });\r\n            });\r\n        }\r\n\r\n        async function loadTeacherData() {\r\n            const token = localStorage.getItem('token');\r\n            if (!token) {\r\n                window.location.href = 'login.html';\r\n                return;\r\n            }\r\n\r\n            try {\r\n                // Cargar perfil\r\n                const userResponse = await fetch('http://localhost:8000/users/me', {\r\n                    headers: { 'Authorization': `Bearer ${token}` }\r\n                });\r\n\r\n                if (!userResponse.ok) throw new Error('Error al cargar perfil');\r\n                currentTeacher = await userResponse.json();\r\n\r\n                // Actualizar UI\r\n                const teacherDisplayName = currentTeacher.full_name || currentTeacher.username || 'Docente';\r\n                const teacherInitials = currentTeacher.full_name\r\n                    ? currentTeacher.full_name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase()\r\n                    : (currentTeacher.username || 'DO').substring(0, 2).toUpperCase();\r\n                document.getElementById('teacherName').textContent = teacherDisplayName;\r\n                document.getElementById('teacherHeroName').textContent = teacherDisplayName;\r\n                document.getElementById('sideTeacherName').textContent = teacherDisplayName;\r\n                document.getElementById('sideTeacherAvatar').textContent = teacherInitials;\r\n                document.getElementById('profileNameDisplay').textContent = currentTeacher.full_name || currentTeacher.username;\r\n                document.getElementById('profileUsernameDisplay').textContent = `@${currentTeacher.username}`;\r\n                \r\n                document.getElementById('profileName').value = currentTeacher.full_name || '';\r\n                document.getElementById('profileEmail').value = currentTeacher.email || '';\r\n\r\n                document.getElementById('profileInitials').textContent = teacherInitials;\r\n\r\n                // Cargar materias\r\n                const subjectsResponse = await fetch('http://localhost:8000/teacher/subjects', {\r\n                    headers: { 'Authorization': `Bearer ${token}` }\r\n                });\r\n\r\n                if (subjectsResponse.ok) {\r\n                    allSubjects = await subjectsResponse.json();\r\n                    document.getElementById('teacherSubjectsCount').textContent = allSubjects.length;\r\n                    renderSubjects();\r\n                    populateSubjectsSelect();\r\n                    renderSubjectWorkMap();\r\n                    renderTeacherWorkQueue();\r\n                }\r\n\r\n                await loadTeacherMoodleData(false);\r\n                await loadTeacherNotifications(false);\r\n                await loadTeacherAdvisorData(false);\r\n                fixMojibakeInDom();\r\n\r\n            } catch (error) {\r\n                console.error('Error:', error);\r\n                showToast('Error al cargar los datos del docente', 'danger');\r\n            }\r\n        }\r\n\r\n        async function loadTeacherMoodleData(showNotification = true) {\r\n            const token = localStorage.getItem('token');\r\n            if (!token) return;\r\n            const tableBody = document.getElementById('teacherMoodleCoursesTableBody');\r\n            if (tableBody) {\r\n                tableBody.innerHTML = '<tr><td colspan=\"5\" class=\"text-center py-4 text-muted\">Cargando cursos Moodle...</td></tr>';\r\n            }\r\n\r\n            try {\r\n                const response = await fetch('http://localhost:8000/teacher/moodle/courses?include_participants=true', {\r\n                    headers: { 'Authorization': `Bearer ${token}` }\r\n                });\r\n                if (!response.ok) throw new Error('No se pudieron cargar cursos Moodle');\r\n                const payload = await response.json();\r\n                teacherMoodleCourses = payload.courses || [];\r\n                renderTeacherMoodleCourses();\r\n                const dashMoodle = document.getElementById('teacherDashboardMoodleCount');\r\n                if (dashMoodle) dashMoodle.textContent = String(teacherMoodleCourses.length);\r\n                renderSubjectWorkMap();\r\n                renderTeacherWorkQueue();\r\n                if (showNotification) showToast('Cursos Moodle actualizados');\r\n                await loadTeacherNotifications(false);\r\n                fixMojibakeInDom();\r\n            } catch (error) {\r\n                console.error(error);\r\n                if (tableBody) {\r\n                    tableBody.innerHTML = '<tr><td colspan=\"5\" class=\"text-center py-4 text-danger\">No fue posible cargar cursos Moodle.</td></tr>';\r\n                }\r\n                document.getElementById('teacherMoodleCourseCount').textContent = '0';\r\n                document.getElementById('teacherMoodleLinkedCount').textContent = '0';\r\n                document.getElementById('teacherMoodleParticipantsCount').textContent = '0';\r\n                const dashMoodle = document.getElementById('teacherDashboardMoodleCount');\r\n                if (dashMoodle) dashMoodle.textContent = '0';\r\n                renderSubjectWorkMap();\r\n                renderTeacherWorkQueue();\r\n                if (showNotification) showToast('Error al cargar Moodle Docente', 'danger');\r\n            }\r\n        }\r\n\r\n        async function loadTeacherNotifications(showToastOnSuccess = false) {\r\n            const token = localStorage.getItem('token');\r\n            if (!token) return;\r\n            const noticeList = document.getElementById('teacherNotificationList');\r\n            if (noticeList) {\r\n                noticeList.innerHTML = '<div class=\"small text-muted px-2 py-2\">Cargando notificaciones...</div>';\r\n            }\r\n            try {\r\n                const response = await fetch('http://localhost:8000/teacher/notifications', {\r\n                    headers: { 'Authorization': `Bearer ${token}` }\r\n                });\r\n                if (!response.ok) throw new Error('No se pudieron cargar notificaciones');\r\n                const payload = await response.json();\r\n                teacherNotifications = payload.items || [];\r\n                const badge = document.getElementById('teacherNoticeCount');\r\n                if (badge) badge.textContent = String(teacherNotifications.length);\r\n                if (noticeList) {\r\n                    noticeList.innerHTML = teacherNotifications.length\r\n                        ? teacherNotifications.map(item => {\r\n                            const level = item.level || 'info';\r\n                            const levelClass = level === 'danger' ? 'text-danger' : level === 'warning' ? 'text-warning' : level === 'success' ? 'text-success' : 'text-primary';\r\n                            return `\r\n                                <div class=\"px-2 py-2 border-bottom\">\r\n                                    <div class=\"fw-semibold ${levelClass}\">${item.title || 'Notificación'}</div>\r\n                                    <div class=\"small text-muted\">${item.message || ''}</div>\r\n                                    <div class=\"small text-secondary\">${item.source || 'Sistema'}</div>\r\n                                </div>\r\n                            `;\r\n                        }).join('')\r\n                        : '<div class=\"small text-muted px-2 py-2\">Sin notificaciones por ahora.</div>';\r\n                }\r\n                renderTeacherDashboardNotifications();\r\n                renderTeacherWorkQueue();\r\n                if (showToastOnSuccess) showToast('Notificaciones actualizadas');\r\n            } catch (error) {\r\n                console.error(error);\r\n                if (noticeList) {\r\n                    noticeList.innerHTML = '<div class=\"small text-danger px-2 py-2\">Error al cargar notificaciones.</div>';\r\n                }\r\n                renderTeacherDashboardNotifications(true);\r\n                renderTeacherWorkQueue();\r\n            }\r\n        }\r\n\r\n        function renderTeacherDashboardNotifications(hasError = false) {\r\n            const dash = document.getElementById('teacherDashNotices');\r\n            if (!dash) return;\r\n            if (hasError) {\r\n                dash.innerHTML = '<div class=\"notice-row text-danger small\">No se pudieron cargar los avisos.</div>';\r\n                return;\r\n            }\r\n            if (!teacherNotifications.length) {\r\n                dash.innerHTML = `\r\n                    <div class=\"notice-row\">\r\n                        <div class=\"fw-semibold text-primary\"><i class=\"bi bi-info-circle me-2\"></i>Sin pendientes por ahora</div>\r\n                        <div class=\"small text-muted\">Cuando haya cierres de actas, mensajes o alertas de Moodle aparecerán aquí.</div>\r\n                    </div>`;\r\n                return;\r\n            }\r\n            dash.innerHTML = teacherNotifications.slice(0, 4).map(item => {\r\n                const level = item.level || 'info';\r\n                const levelClass = level === 'danger' ? 'text-danger' : level === 'warning' ? 'text-warning' : level === 'success' ? 'text-success' : 'text-primary';\r\n                return `\r\n                    <div class=\"notice-row\">\r\n                        <div class=\"d-flex align-items-start gap-2\">\r\n                            <i class=\"bi bi-info-circle-fill ${levelClass} mt-1\"></i>\r\n                            <div>\r\n                                <div class=\"fw-semibold ${levelClass}\">${item.title || 'Notificación'}</div>\r\n                                <div class=\"small text-muted\">${item.message || ''}</div>\r\n                                <div class=\"small text-secondary\">${item.source || 'Sistema'}</div>\r\n                            </div>\r\n                        </div>\r\n                    </div>`;\r\n            }).join('');\r\n        }\r\n\r\n        function normalizeText(value) {\r\n            return String(value || '').trim().toLowerCase();\r\n        }\r\n\r\n        function escapeJs(value) {\r\n            return String(value || '').replace(/\\\\/g, '\\\\\\\\').replace(/'/g, \"\\\\'\");\r\n        }\r\n\r\n        function subjectHasMoodle(subject) {\r\n            const subjectId = String(subject.subject_id || subject.id || '');\r\n            const subjectName = normalizeText(subject.name);\r\n            return teacherMoodleCourses.some(course => {\r\n                const courseSubjectId = String(course.subject_id || course.assignment_subject_id || '');\r\n                const courseName = normalizeText(course.subject_name || course.moodle_course?.displayname);\r\n                return Boolean(course.moodle_course_id) && (\r\n                    (subjectId && courseSubjectId && subjectId === courseSubjectId) ||\r\n                    (subjectName && courseName && courseName.includes(subjectName))\r\n                );\r\n            });\r\n        }\r\n\r\n        function getSelectedGradeStats() {\r\n            const students = _currentGradeStudents || [];\r\n            if (!students.length) return null;\r\n            const total = students.length;\r\n            const captured = students.filter(s => s.score !== null && s.score !== undefined && s.score !== '').length;\r\n            const missingDocs = students.filter(s => !s.has_document).length;\r\n            const failed = students.filter(s => s.status === 'Reprobada').length;\r\n            const approved = students.filter(s => s.status === 'Aprobada').length;\r\n            return { total, captured, pendingGrades: total - captured, missingDocs, failed, approved };\r\n        }\r\n\r\n        function renderSubjectWorkMap() {\r\n            const map = document.getElementById('teacherSubjectMap');\r\n            const summary = document.getElementById('teacherSubjectsSummary');\r\n            const targets = [map, summary].filter(Boolean);\r\n            if (!targets.length) return;\r\n\r\n            if (!allSubjects.length) {\r\n                targets.forEach(el => {\r\n                    el.innerHTML = '<div class=\"col-12\"><div class=\"notice-row text-muted small\">No hay materias asignadas en el ciclo activo.</div></div>';\r\n                });\r\n                return;\r\n            }\r\n\r\n            const cards = allSubjects.slice(0, 6).map(subject => {\r\n                const hasMoodle = subjectHasMoodle(subject);\r\n                const moodleBadge = hasMoodle\r\n                    ? '<span class=\"badge bg-success-subtle text-success border border-success-subtle\">Moodle activo</span>'\r\n                    : '<span class=\"badge bg-warning-subtle text-warning border border-warning-subtle\">Revisar Moodle</span>';\r\n                const progress = hasMoodle ? 70 : 35;\r\n                return `\r\n                    <div class=\"col-md-6 col-xl-4\">\r\n                        <div class=\"subject-summary-card\">\r\n                            <div class=\"d-flex justify-content-between align-items-start gap-2 mb-2\">\r\n                                <div class=\"min-w-0\">\r\n                                    <div class=\"fw-bold text-truncate\">${subject.name || 'Materia'}</div>\r\n                                    <div class=\"meta-line\">Grupo ${subject.group_name || '-'} · ${subject.career || '-'} · Sem. ${subject.semester || '-'}</div>\r\n                                </div>\r\n                                ${moodleBadge}\r\n                            </div>\r\n                            <div class=\"progress-thin mb-3\" title=\"Preparación operativa\"><span style=\"width:${progress}%\"></span></div>\r\n                            <div class=\"d-flex gap-2 flex-wrap\">\r\n                                <button class=\"btn btn-sm btn-primary rounded-pill\" onclick=\"startGradeCapture('${escapeJs(subject.id)}')\">\r\n                                    <i class=\"bi bi-check2-square me-1\"></i>Capturar\r\n                                </button>\r\n                                <button class=\"btn btn-sm btn-outline-primary rounded-pill\" onclick=\"switchView('view-moodle')\">\r\n                                    <i class=\"bi bi-laptop me-1\"></i>Moodle\r\n                                </button>\r\n                            </div>\r\n                        </div>\r\n                    </div>`;\r\n            }).join('');\r\n\r\n            if (map) map.innerHTML = cards;\r\n            if (summary) summary.innerHTML = cards;\r\n        }\r\n\r\n        function renderTeacherWorkQueue() {\r\n            const queue = document.getElementById('teacherWorkQueue');\r\n            const count = document.getElementById('teacherWorkQueueCount');\r\n            if (!queue) return;\r\n\r\n            const stats = getSelectedGradeStats();\r\n            const unlinkedMoodle = allSubjects.filter(subject => !subjectHasMoodle(subject)).length;\r\n            const riskStudents = teacherAdvisorStudents.filter(s => Boolean(s.risk) || Number(s.avg || 10) < 6).length;\r\n            const now = new Date();\r\n            const nextSessions = teacherAdvisorSessions.filter(s => {\r\n                const date = new Date(s.scheduled_at);\r\n                return date >= now && s.status !== 'Cancelada' && s.status !== 'Realizada';\r\n            }).length;\r\n            const noticeCount = teacherNotifications.length;\r\n\r\n            const items = [];\r\n            if (stats?.pendingGrades) {\r\n                items.push({\r\n                    icon: 'bi-check2-square',\r\n                    color: 'text-danger',\r\n                    bg: 'bg-danger-subtle',\r\n                    title: `${stats.pendingGrades} calificaciones pendientes`,\r\n                    text: 'Termina la captura del grupo seleccionado.',\r\n                    action: 'Continuar captura',\r\n                    fn: \"switchView('view-calificaciones')\"\r\n                });\r\n            }\r\n            if (stats?.missingDocs) {\r\n                items.push({\r\n                    icon: 'bi-paperclip',\r\n                    color: 'text-warning',\r\n                    bg: 'bg-warning-subtle',\r\n                    title: `${stats.missingDocs} comprobantes faltantes`,\r\n                    text: 'Adjunta evidencia antes de imprimir el formato.',\r\n                    action: 'Ver comprobantes',\r\n                    fn: \"switchView('view-calificaciones')\"\r\n                });\r\n            }\r\n            if (riskStudents) {\r\n                items.push({\r\n                    icon: 'bi-exclamation-triangle-fill',\r\n                    color: 'text-danger',\r\n                    bg: 'bg-danger-subtle',\r\n                    title: `${riskStudents} alumnos en riesgo`,\r\n                    text: 'Prioriza mensaje o asesoría académica.',\r\n                    action: 'Atender asesoría',\r\n                    fn: \"switchView('view-asesor')\"\r\n                });\r\n            }\r\n            if (nextSessions) {\r\n                items.push({\r\n                    icon: 'bi-calendar-check-fill',\r\n                    color: 'text-success',\r\n                    bg: 'bg-success-subtle',\r\n                    title: `${nextSessions} sesiones próximas`,\r\n                    text: 'Revisa agenda y confirma seguimiento.',\r\n                    action: 'Ver sesiones',\r\n                    fn: \"switchView('view-asesor')\"\r\n                });\r\n            }\r\n            if (unlinkedMoodle) {\r\n                items.push({\r\n                    icon: 'bi-link-45deg',\r\n                    color: 'text-warning',\r\n                    bg: 'bg-warning-subtle',\r\n                    title: `${unlinkedMoodle} materias por revisar en Moodle`,\r\n                    text: 'Confirma que los cursos estén vinculados.',\r\n                    action: 'Revisar Moodle',\r\n                    fn: \"switchView('view-moodle')\"\r\n                });\r\n            }\r\n            if (noticeCount) {\r\n                items.push({\r\n                    icon: 'bi-bell-fill',\r\n                    color: 'text-primary',\r\n                    bg: 'bg-primary-subtle',\r\n                    title: `${noticeCount} avisos activos`,\r\n                    text: 'Consulta mensajes institucionales y del sistema.',\r\n                    action: 'Ver avisos',\r\n                    fn: \"loadTeacherNotifications(true)\"\r\n                });\r\n            }\r\n\r\n            if (count) count.textContent = `${items.length} pendientes`;\r\n            if (!items.length) {\r\n                queue.innerHTML = `\r\n                    <div class=\"col-12\">\r\n                        <div class=\"notice-row\">\r\n                            <div class=\"fw-semibold text-success\"><i class=\"bi bi-check-circle-fill me-2\"></i>Todo en orden</div>\r\n                            <div class=\"small text-muted\">No hay tareas urgentes con la información disponible.</div>\r\n                        </div>\r\n                    </div>`;\r\n                return;\r\n            }\r\n\r\n            queue.innerHTML = items.slice(0, 6).map(item => `\r\n                <div class=\"col-md-6 col-xl-4\">\r\n                    <div class=\"priority-card\">\r\n                        <div class=\"d-flex align-items-start gap-3\">\r\n                            <span class=\"icon ${item.bg} ${item.color}\"><i class=\"bi ${item.icon}\"></i></span>\r\n                            <div class=\"flex-fill\">\r\n                                <div class=\"fw-bold\">${item.title}</div>\r\n                                <div class=\"small text-muted mb-2\">${item.text}</div>\r\n                                <button class=\"btn btn-sm btn-outline-primary rounded-pill\" onclick=\"${item.fn}\">${item.action}</button>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>`).join('');\r\n        }\r\n\r\n        function advisorRiskBadge(risk) {\r\n            if (!risk) return '<span class=\"badge bg-success-subtle text-success border border-success-subtle\">Sin riesgo</span>';\r\n            return `<span class=\"badge bg-danger-subtle text-danger border border-danger-subtle\">${risk} en riesgo</span>`;\r\n        }\r\n\r\n        function advisorAvgBadge(avg) {\r\n            if (avg === null || avg === undefined) return '<span class=\"badge bg-secondary-subtle text-secondary border\">Sin calif.</span>';\r\n            const cls = avg >= 8 ? 'bg-success-subtle text-success border-success-subtle' : avg >= 6 ? 'bg-warning-subtle text-warning border-warning-subtle' : 'bg-danger-subtle text-danger border-danger-subtle';\r\n            return `<span class=\"badge ${cls} border\">${avg.toFixed(1)}</span>`;\r\n        }\r\n\r\n        function sessionStatusBadge(status) {\r\n            const map = {\r\n                'Pendiente': 'bg-warning-subtle text-warning border-warning-subtle',\r\n                'Confirmada': 'bg-success-subtle text-success border-success-subtle',\r\n                'Cancelada': 'bg-danger-subtle text-danger border-danger-subtle',\r\n                'Realizada': 'bg-secondary-subtle text-secondary border-secondary-subtle',\r\n            };\r\n            return `<span class=\"badge border ${map[status] || 'bg-light text-dark'}\">${status}</span>`;\r\n        }\r\n\r\n        function formatSessionDate(iso) {\r\n            if (!iso) return '-';\r\n            const d = new Date(iso);\r\n            return d.toLocaleDateString('es-MX', { day: '2-digit', month: 'short', year: 'numeric' }) + ' ' + d.toLocaleTimeString('es-MX', { hour: '2-digit', minute: '2-digit' });\r\n        }\r\n\r\n        async function loadTeacherAdvisorData(showToastOnSuccess = false) {\r\n            const token = localStorage.getItem('token');\r\n            if (!token) return;\r\n            const studentsEl = document.getElementById('teacherAdvisorStudentsBody');\r\n            if (studentsEl) studentsEl.innerHTML = '<div class=\"col-12 text-center text-muted py-4\">Cargando alumnos...</div>';\r\n\r\n            try {\r\n                const [studentsRes, sessionsRes] = await Promise.all([\r\n                    fetch('http://localhost:8000/teacher/advisor/students', { headers: { 'Authorization': `Bearer ${token}` } }),\r\n                    fetch('http://localhost:8000/teacher/advisor/sessions', { headers: { 'Authorization': `Bearer ${token}` } }),\r\n                ]);\r\n                if (!studentsRes.ok) throw new Error('No se pudo cargar asesoría');\r\n                const studentsPayload = await studentsRes.json();\r\n                teacherAdvisorStudents = studentsPayload.students || [];\r\n                const sessions = sessionsRes.ok ? (await sessionsRes.json()).sessions || [] : [];\r\n                teacherAdvisorSessions = sessions;\r\n\r\n                const optionsHtml = '<option value=\"\">Selecciona alumno...</option>' +\r\n                    teacherAdvisorStudents.map(s => `<option value=\"${s.username}\">${s.full_name || s.username} (${s.username})</option>`).join('');\r\n                ['advisorMessageStudent', 'sessionStudent'].forEach(id => {\r\n                    const el = document.getElementById(id);\r\n                    if (el) el.innerHTML = optionsHtml;\r\n                });\r\n\r\n                if (studentsEl) {\r\n                    studentsEl.innerHTML = teacherAdvisorStudents.length\r\n                        ? teacherAdvisorStudents.map(s => `\r\n                            <div class=\"col-md-6 col-xl-4\">\r\n                              <div class=\"border rounded-3 p-3 h-100\" style=\"background:#f8faff\">\r\n                                <div class=\"d-flex align-items-center gap-2 mb-2\">\r\n                                  <div class=\"rounded-circle bg-primary text-white d-flex align-items-center justify-content-center fw-bold\" style=\"width:36px;height:36px;font-size:.85rem;flex-shrink:0\">${(s.full_name||s.username).charAt(0).toUpperCase()}</div>\r\n                                  <div class=\"min-w-0\">\r\n                                    <div class=\"fw-semibold text-truncate\" style=\"max-width:160px\">${s.full_name || s.username}</div>\r\n                                    <div class=\"small text-muted\">${s.username} · ${s.source === 'direct' ? 'Asignado' : 'Grupo'}</div>\r\n                                  </div>\r\n                                </div>\r\n                                <div class=\"small text-muted mb-2\">${s.carrera || '-'} · ${s.period_label || '-'}</div>\r\n                                <div class=\"d-flex gap-1 flex-wrap mb-3\">\r\n                                  <span class=\"badge bg-primary-subtle text-primary border border-primary-subtle\">${s.approved || 0}/${s.total || 0} apr.</span>\r\n                                  ${advisorAvgBadge(s.avg)}\r\n                                  ${advisorRiskBadge(s.risk)}\r\n                                </div>\r\n                                <div class=\"d-flex gap-2\">\r\n                                  <button type=\"button\" class=\"btn btn-sm btn-outline-primary rounded-pill flex-fill\" onclick=\"prefillAdvisorMessage('${s.username}')\"><i class=\"bi bi-chat-dots me-1\"></i>Mensaje</button>\r\n                                  <button type=\"button\" class=\"btn btn-sm btn-outline-success rounded-pill flex-fill\" onclick=\"prefillAdvisorSession('${s.username}')\"><i class=\"bi bi-calendar-plus me-1\"></i>Agendar</button>\r\n                                </div>\r\n                                <button type=\"button\" class=\"btn btn-sm btn-light border rounded-pill w-100 mt-2\" onclick=\"openAdvisorStudentContext('${s.username}')\">\r\n                                  <i class=\"bi bi-clipboard2-pulse me-1\"></i>Seguimiento rápido\r\n                                </button>\r\n                              </div>\r\n                            </div>`)\r\n                        .join('')\r\n                        : '<div class=\"col-12 text-center text-muted py-4\">No tienes alumnos asignados en asesoría.</div>';\r\n                }\r\n\r\n                renderAdvisorSessions(sessions);\r\n                renderTeacherWorkQueue();\r\n                if (showToastOnSuccess) showToast('Asesoría actualizada');\r\n            } catch (error) {\r\n                console.error(error);\r\n                if (studentsEl) studentsEl.innerHTML = '<div class=\"col-12 text-center text-danger py-4\">Error al cargar asesorías.</div>';\r\n                renderTeacherWorkQueue();\r\n            }\r\n        }\r\n\r\n        function renderAdvisorSessions(sessions) {\r\n            const el = document.getElementById('teacherSessionsList');\r\n            const badge = document.getElementById('sessionCountBadge');\r\n            if (!el) return;\r\n            if (badge) badge.textContent = String(sessions.length);\r\n            if (!sessions.length) {\r\n                el.innerHTML = '<div class=\"text-center text-muted py-3 small\">No hay sesiones agendadas todavía.</div>';\r\n                return;\r\n            }\r\n            const now = new Date();\r\n            const upcoming = sessions.filter(s => new Date(s.scheduled_at) >= now && s.status !== 'Cancelada' && s.status !== 'Realizada');\r\n            const past = sessions.filter(s => new Date(s.scheduled_at) < now || s.status === 'Realizada' || s.status === 'Cancelada');\r\n            let html = '';\r\n            if (upcoming.length) {\r\n                html += `<div class=\"fw-semibold small text-success mb-2\"><i class=\"bi bi-clock-fill me-1\"></i>Próximas (${upcoming.length})</div>`;\r\n                html += upcoming.map(s => sessionRow(s)).join('');\r\n            }\r\n            if (past.length) {\r\n                html += `<div class=\"fw-semibold small text-muted mt-3 mb-2\"><i class=\"bi bi-archive-fill me-1\"></i>Historial (${past.length})</div>`;\r\n                html += past.slice(0, 10).map(s => sessionRow(s)).join('');\r\n            }\r\n            el.innerHTML = html;\r\n        }\r\n\r\n        function sessionRow(s) {\r\n            const actionBtns = s.status === 'Pendiente'\r\n                ? `<button type=\"button\" class=\"btn btn-xs btn-outline-success rounded-pill\" onclick=\"updateAdvisorSession(${s.id},'Confirmada')\">Confirmar</button>\r\n                   <button type=\"button\" class=\"btn btn-xs btn-outline-secondary rounded-pill\" onclick=\"updateAdvisorSession(${s.id},'Realizada')\">Realizada</button>\r\n                   <button type=\"button\" class=\"btn btn-xs btn-outline-danger rounded-pill\" onclick=\"updateAdvisorSession(${s.id},'Cancelada')\">Cancelar</button>`\r\n                : s.status === 'Confirmada'\r\n                ? `<button type=\"button\" class=\"btn btn-xs btn-outline-secondary rounded-pill\" onclick=\"updateAdvisorSession(${s.id},'Realizada')\">Marcar realizada</button>\r\n                   <button type=\"button\" class=\"btn btn-xs btn-outline-danger rounded-pill\" onclick=\"updateAdvisorSession(${s.id},'Cancelada')\">Cancelar</button>`\r\n                : '';\r\n            return `\r\n                <div class=\"border rounded-3 p-3 mb-2 d-flex align-items-start gap-3 flex-wrap\">\r\n                  <div class=\"flex-fill\">\r\n                    <div class=\"d-flex align-items-center gap-2 flex-wrap mb-1\">\r\n                      ${sessionStatusBadge(s.status)}\r\n                      <span class=\"fw-semibold small\">${s.student_name || s.student_username}</span>\r\n                      <span class=\"text-muted small ms-auto\">${formatSessionDate(s.scheduled_at)} · ${s.duration_minutes} min</span>\r\n                    </div>\r\n                    <div class=\"small text-secondary\">${s.topic}</div>\r\n                    ${s.notes ? `<div class=\"small text-muted mt-1\"><i class=\"bi bi-sticky-fill me-1\"></i>${s.notes}</div>` : ''}\r\n                  </div>\r\n                  <div class=\"d-flex gap-1 flex-wrap\">${actionBtns}</div>\r\n                </div>`;\r\n        }\r\n\r\n        function prefillAdvisorMessage(username) {\r\n            const select = document.getElementById('advisorMessageStudent');\r\n            if (select) select.value = username;\r\n            switchView('view-asesor');\r\n            document.getElementById('advisorMessageTitle')?.focus();\r\n        }\r\n\r\n        function prefillAdvisorSession(username) {\r\n            const select = document.getElementById('sessionStudent');\r\n            if (select) select.value = username;\r\n            const now = new Date();\r\n            now.setMinutes(0, 0, 0);\r\n            now.setHours(now.getHours() + 1);\r\n            const local = new Date(now.getTime() - now.getTimezoneOffset() * 60000).toISOString().slice(0, 16);\r\n            const dateEl = document.getElementById('sessionDate');\r\n            if (dateEl && !dateEl.value) dateEl.value = local;\r\n            switchView('view-asesor');\r\n            document.getElementById('sessionTopic')?.focus();\r\n        }\r\n\r\n        function openAdvisorStudentContext(username) {\r\n            const student = teacherAdvisorStudents.find(s => s.username === username);\r\n            if (!student) return;\r\n            const title = student.risk\r\n                ? `Seguimiento de ${student.full_name || student.username}: ${student.risk} en riesgo`\r\n                : `Seguimiento académico de ${student.full_name || student.username}`;\r\n            const body = student.risk\r\n                ? `Hola ${student.full_name || student.username}, revisemos tu avance académico para atender las materias en riesgo y definir una acción de recuperación.`\r\n                : `Hola ${student.full_name || student.username}, te comparto seguimiento académico para mantener tu avance en orden.`;\r\n            const messageStudent = document.getElementById('advisorMessageStudent');\r\n            const sessionStudent = document.getElementById('sessionStudent');\r\n            if (messageStudent) messageStudent.value = username;\r\n            if (sessionStudent) sessionStudent.value = username;\r\n            const titleInput = document.getElementById('advisorMessageTitle');\r\n            const bodyInput = document.getElementById('advisorMessageBody');\r\n            if (titleInput && !titleInput.value) titleInput.value = title;\r\n            if (bodyInput && !bodyInput.value) bodyInput.value = body;\r\n            showToast('Seguimiento preparado para mensaje o asesoría', 'info');\r\n            document.getElementById('advisorMessageBody')?.focus();\r\n        }\r\n\r\n        async function sendAdvisorMessage(event) {\r\n            event.preventDefault();\r\n            const token = localStorage.getItem('token');\r\n            const studentUsername = document.getElementById('advisorMessageStudent')?.value || '';\r\n            const title = document.getElementById('advisorMessageTitle')?.value?.trim() || '';\r\n            const message = document.getElementById('advisorMessageBody')?.value?.trim() || '';\r\n            if (!studentUsername || !title || !message) {\r\n                showToast('Completa alumno, asunto y mensaje', 'warning');\r\n                return;\r\n            }\r\n            try {\r\n                const response = await fetch('http://localhost:8000/teacher/advisor/messages', {\r\n                    method: 'POST',\r\n                    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },\r\n                    body: JSON.stringify({ student_username: studentUsername, title, message })\r\n                });\r\n                if (!response.ok) {\r\n                    const p = await response.json().catch(() => ({}));\r\n                    showToast(p?.detail || 'No se pudo enviar el mensaje', 'danger');\r\n                    return;\r\n                }\r\n                showToast('Mensaje enviado al alumno');\r\n                document.getElementById('teacherAdvisorMessageForm')?.reset();\r\n                await loadTeacherNotifications(false);\r\n                await loadTeacherAdvisorData(false);\r\n            } catch (error) {\r\n                console.error(error);\r\n                showToast('Error de conexión al enviar mensaje', 'danger');\r\n            }\r\n        }\r\n\r\n        async function sendAdvisorSession(event) {\r\n            event.preventDefault();\r\n            const token = localStorage.getItem('token');\r\n            const student_username = document.getElementById('sessionStudent')?.value || '';\r\n            const scheduled_at = document.getElementById('sessionDate')?.value || '';\r\n            const duration_minutes = parseInt(document.getElementById('sessionDuration')?.value || '30');\r\n            const topic = document.getElementById('sessionTopic')?.value?.trim() || '';\r\n            const notes = document.getElementById('sessionNotes')?.value?.trim() || '';\r\n            if (!student_username || !scheduled_at || !topic) {\r\n                showToast('Completa alumno, fecha y tema', 'warning');\r\n                return;\r\n            }\r\n            try {\r\n                const response = await fetch('http://localhost:8000/teacher/advisor/sessions', {\r\n                    method: 'POST',\r\n                    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },\r\n                    body: JSON.stringify({ student_username, scheduled_at: new Date(scheduled_at).toISOString(), duration_minutes, topic, notes: notes || null })\r\n                });\r\n                if (!response.ok) {\r\n                    const p = await response.json().catch(() => ({}));\r\n                    showToast(p?.detail || 'No se pudo agendar la sesión', 'danger');\r\n                    return;\r\n                }\r\n                showToast('Sesión agendada. El alumno recibirá una notificación.', 'success');\r\n                document.getElementById('teacherAdvisorSessionForm')?.reset();\r\n                await loadTeacherAdvisorData(false);\r\n            } catch (error) {\r\n                console.error(error);\r\n                showToast('Error de conexión al agendar sesión', 'danger');\r\n            }\r\n        }\r\n\r\n        async function updateAdvisorSession(sessionId, status) {\r\n            const token = localStorage.getItem('token');\r\n            try {\r\n                const response = await fetch(`http://localhost:8000/teacher/advisor/sessions/${sessionId}`, {\r\n                    method: 'PATCH',\r\n                    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },\r\n                    body: JSON.stringify({ status })\r\n                });\r\n                if (!response.ok) throw new Error();\r\n                showToast(`Sesión marcada como: ${status}`);\r\n                await loadTeacherAdvisorData(false);\r\n            } catch {\r\n                showToast('No se pudo actualizar la sesión', 'danger');\r\n            }\r\n        }\r\n\r\n        async function openTeacherMoodleInSession(targetUrl = '') {\r\n            const token = localStorage.getItem('token');\r\n            if (!token) return;\r\n            try {\r\n                const endpoint = `http://localhost:8000/users/me/moodle-launch?target_url=${encodeURIComponent(targetUrl || 'http://localhost:8080/my/')}`;\r\n                const response = await fetch(endpoint, {\r\n                    headers: { 'Authorization': `Bearer ${token}` }\r\n                });\r\n                if (!response.ok) {\r\n                    showToast('No fue posible preparar el acceso a Moodle', 'danger');\r\n                    return;\r\n                }\r\n                const payload = await response.json();\r\n                if (!payload.can_auto_login) {\r\n                    showToast('Tu cuenta docente aún no tiene acceso Moodle completo', 'warning');\r\n                    window.open(payload.url || payload.login_url || 'http://localhost:8080/login/index.php', '_blank');\r\n                    return;\r\n                }\r\n\r\n                const form = document.createElement('form');\r\n                form.method = 'POST';\r\n                form.action = payload.login_post_url || 'http://localhost:8080/login/index.php';\r\n                form.target = '_blank';\r\n                form.style.display = 'none';\r\n\r\n                const fields = {\r\n                    username: payload.username || '',\r\n                    password: payload.password || '',\r\n                    rememberusername: 1,\r\n                    wantsurl: payload.target_url || payload.url || ''\r\n                };\r\n                Object.entries(fields).forEach(([key, value]) => {\r\n                    const input = document.createElement('input');\r\n                    input.type = 'hidden';\r\n                    input.name = key;\r\n                    input.value = String(value ? '');\r\n                    form.appendChild(input);\r\n                });\r\n                document.body.appendChild(form);\r\n                form.submit();\r\n                form.remove();\r\n            } catch (error) {\r\n                console.error(error);\r\n                showToast('Error de conexión al abrir Moodle', 'danger');\r\n            }\r\n        }\r\n\r\n        async function goTeacherToMoodle() {\r\n            await openTeacherMoodleInSession('http://localhost:8080/my/courses.php');\r\n        }\r\n\r\n        function renderTeacherMoodleCourses() {\r\n            const tableBody = document.getElementById('teacherMoodleCoursesTableBody');\r\n            if (!tableBody) return;\r\n\r\n            const totalCourses = teacherMoodleCourses.length;\r\n            const linkedCourses = teacherMoodleCourses.filter(c => Boolean(c.moodle_course_id)).length;\r\n            const participants = teacherMoodleCourses.reduce((sum, c) => sum + Number(c.participants_count || 0), 0);\r\n            document.getElementById('teacherMoodleCourseCount').textContent = String(totalCourses);\r\n            document.getElementById('teacherMoodleLinkedCount').textContent = String(linkedCourses);\r\n            document.getElementById('teacherMoodleParticipantsCount').textContent = String(participants);\r\n            renderSubjectWorkMap();\r\n            renderTeacherWorkQueue();\r\n\r\n            if (!teacherMoodleCourses.length) {\r\n                tableBody.innerHTML = '<tr><td colspan=\"5\" class=\"text-center py-4 text-muted\">No tienes materias sincronizadas con Moodle en el ciclo activo.</td></tr>';\r\n                return;\r\n            }\r\n\r\n            tableBody.innerHTML = teacherMoodleCourses.map(course => `\r\n                <tr>\r\n                    <td>\r\n                        <div class=\"fw-bold\">${course.moodle_course?.displayname || course.subject_name || 'Curso Moodle'}</div>\r\n                        <div class=\"small text-muted\">ID Moodle: ${course.moodle_course_id || '-'}</div>\r\n                    </td>\r\n                    <td>${course.subject_name || '-'}</td>\r\n                    <td>${course.semester || '-'}</td>\r\n                    <td>${course.participants_count ? '-'}</td>\r\n                    <td>\r\n                        <button class=\"btn btn-sm btn-outline-primary rounded-pill me-1\" onclick=\"loadTeacherMoodleCourseDetail(${course.moodle_course_id}, '${(course.subject_name || '').replace(/'/g, \"\\\\'\")}')\">\r\n                            Ver detalles\r\n                        </button>\r\n                        <button class=\"btn btn-sm btn-primary rounded-pill\" onclick=\"window.open('${course.moodle_course?.view_url || ''}', '_blank')\">\r\n                            Abrir curso\r\n                        </button>\r\n                    </td>\r\n                </tr>\r\n            `).join('');\r\n        }\r\n\r\n        async function loadTeacherMoodleCourseDetail(courseId, subjectName) {\r\n            const token = localStorage.getItem('token');\r\n            if (!token) return;\r\n\r\n            document.getElementById('teacherMoodleCourseInfo').textContent = `${subjectName || 'Curso'} · Moodle #${courseId}`;\r\n            document.getElementById('teacherMoodleContents').innerHTML = '<div class=\"text-muted small\">Cargando contenidos...</div>';\r\n            document.getElementById('teacherMoodleParticipants').innerHTML = '<div class=\"text-muted small\">Cargando participantes...</div>';\r\n\r\n            try {\r\n                const [contentsRes, participantsRes] = await Promise.all([\r\n                    fetch(`http://localhost:8000/teacher/moodle/courses/${courseId}/contents`, {\r\n                        headers: { 'Authorization': `Bearer ${token}` }\r\n                    }),\r\n                    fetch(`http://localhost:8000/teacher/moodle/courses/${courseId}/participants`, {\r\n                        headers: { 'Authorization': `Bearer ${token}` }\r\n                    }),\r\n                ]);\r\n\r\n                if (!contentsRes.ok) throw new Error('No se pudo cargar contenido del curso');\r\n                if (!participantsRes.ok) throw new Error('No se pudo cargar participantes');\r\n\r\n                const contentsPayload = await contentsRes.json();\r\n                const participantsPayload = await participantsRes.json();\r\n                const sections = contentsPayload.sections || [];\r\n                const users = participantsPayload.users || [];\r\n\r\n                document.getElementById('teacherMoodleContents').innerHTML = sections.length\r\n                    ? sections.map(section => {\r\n                        const modules = section.modules || [];\r\n                        const modulesHtml = modules.length\r\n                            ? modules.slice(0, 5).map(module => `<div class=\"small text-muted\">• ${module.name || 'Recurso'} (${module.modname || 'módulo'})</div>`).join('')\r\n                            : '<div class=\"small text-muted\">Sin módulos en esta sección.</div>';\r\n                        return `\r\n                            <div class=\"border rounded-3 p-3\">\r\n                                <div class=\"fw-semibold\">${section.name || 'Sección sin nombre'}</div>\r\n                                <div class=\"small text-muted mb-2\">Módulos: ${modules.length}</div>\r\n                                ${modulesHtml}\r\n                            </div>\r\n                        `;\r\n                    }).join('')\r\n                    : '<div class=\"text-muted small\">Este curso aún no tiene secciones visibles.</div>';\r\n\r\n                document.getElementById('teacherMoodleParticipants').innerHTML = users.length\r\n                    ? users.slice(0, 20).map(user => `\r\n                        <div class=\"border rounded-3 p-2\">\r\n                            <div class=\"fw-semibold\">${user.fullname || user.username || 'Usuario'}</div>\r\n                            <div class=\"small text-muted\">${user.email || '-'}</div>\r\n                        </div>\r\n                    `).join('')\r\n                    : '<div class=\"text-muted small\">No hay participantes visibles en Moodle.</div>';\r\n            } catch (error) {\r\n                console.error(error);\r\n                document.getElementById('teacherMoodleContents').innerHTML = '<div class=\"text-danger small\">No se pudo cargar el contenido del curso.</div>';\r\n                document.getElementById('teacherMoodleParticipants').innerHTML = '<div class=\"text-danger small\">No se pudieron cargar los participantes.</div>';\r\n                showToast('Error al consultar detalle Moodle', 'danger');\r\n            }\r\n        }\r\n\r\n        function renderSubjects() {\r\n            const tbody = document.getElementById('teacherSubjectsTableBody');\r\n            tbody.innerHTML = '';\r\n\r\n            if (allSubjects.length === 0) {\r\n                tbody.innerHTML = '<tr><td colspan=\"5\" class=\"text-center py-4 text-muted\">No tienes materias asignadas.</td></tr>';\r\n                renderSubjectWorkMap();\r\n                renderTeacherWorkQueue();\r\n                return;\r\n            }\r\n\r\n            // allSubjects viene del endpoint /teacher/subjects que ahora devuelve asignaciones\r\n            // Cada elemento tiene: id (=assignment_id), name, career, semester, credits\r\n            allSubjects.forEach(subject => {\r\n                const tr = document.createElement('tr');\r\n                tr.innerHTML = `\r\n                    <td><span class=\"badge bg-light text-dark border\">#${subject.subject_id}</span></td>\r\n                    <td class=\"fw-bold\">${subject.name}<div class=\"small text-muted mt-1\">Grupo ${subject.group_name || '—'}</div></td>\r\n                    <td>${subject.career}</td>\r\n                    <td>${subject.semester}</td>\r\n                    <td>${subject.credits}</td>\r\n                `;\r\n                tbody.appendChild(tr);\r\n            });\r\n            renderSubjectWorkMap();\r\n            renderTeacherWorkQueue();\r\n        }\r\n\r\n        function populateSubjectsSelect() {\r\n            const select = document.getElementById('selectSubjectForGrades');\r\n            select.innerHTML = '<option value=\"\">Selecciona una materia...</option>';\r\n            allSubjects.forEach(subject => {\r\n                const option = document.createElement('option');\r\n                option.value = subject.id;\r\n                option.textContent = `${subject.name} · Grupo ${subject.group_name || '—'} (${subject.career})`;\r\n                select.appendChild(option);\r\n            });\r\n            renderSubjectPickerCards();\r\n        }\r\n\r\n        function renderSubjectPickerCards() {\r\n            const grid = document.getElementById('subjectPickerGrid');\r\n            if (!grid) return;\r\n            if (!allSubjects.length) {\r\n                grid.innerHTML = '<div class=\"notice-row text-muted small\">No tienes materias asignadas en el ciclo activo.</div>';\r\n                return;\r\n            }\r\n            grid.innerHTML = allSubjects.map(subject => `\r\n                <div class=\"subject-picker-card\" id=\"spc_${subject.id}\" onclick=\"pickSubject('${subject.id}')\">\r\n                    <div class=\"sp-icon\"><i class=\"bi bi-journal-bookmark-fill\"></i></div>\r\n                    <div class=\"sp-name\">${subject.name}</div>\r\n                    <div class=\"sp-meta\">Grupo ${subject.group_name || '—'} · ${subject.career}</div>\r\n                    <div class=\"sp-meta\">Semestre ${subject.semester} · ${subject.credits} créditos</div>\r\n                </div>`).join('');\r\n        }\r\n\r\n        function pickSubject(assignmentId) {\r\n            document.querySelectorAll('.subject-picker-card').forEach(c => c.classList.remove('selected'));\r\n            const card = document.getElementById(`spc_${assignmentId}`);\r\n            if (card) card.classList.add('selected');\r\n            const select = document.getElementById('selectSubjectForGrades');\r\n            if (select) select.value = assignmentId;\r\n            loadStudentsForSubject();\r\n        }\r\n\r\n        function resetSubjectPicker() {\r\n            const select = document.getElementById('selectSubjectForGrades');\r\n            if (select) select.value = '';\r\n            document.querySelectorAll('.subject-picker-card').forEach(c => c.classList.remove('selected'));\r\n            document.getElementById('subjectPickerPanel').style.display = '';\r\n            document.getElementById('gradeStatsPanel').style.display = 'none';\r\n            document.getElementById('gradingArea').style.display = 'none';\r\n            document.getElementById('gradingPlaceholder').style.display = 'none';\r\n            document.getElementById('btnSaveAll').style.display = 'none';\r\n            document.getElementById('btnPrintFormat').style.display = 'none';\r\n            _currentGradeStudents = [];\r\n            _currentGradeGroupTab = '';\r\n            updateStepper(1);\r\n            renderTeacherWorkQueue();\r\n        }\r\n\r\n        function updateStepper(step) {\r\n            const steps = [1,2,3,4];\r\n            steps.forEach(n => {\r\n                const el = document.getElementById(`gstep${n}`);\r\n                const conn = document.getElementById(`gconn${n}`);\r\n                if (!el) return;\r\n                el.classList.remove('active','done');\r\n                if (n < step) { el.classList.add('done'); if(conn) conn.classList.add('done'); }\r\n                else if (n === step) { el.classList.add('active'); if(conn) conn.classList.remove('done'); }\r\n                else { if(conn) conn.classList.remove('done'); }\r\n                // Fix icon for done steps\r\n                const numEl = el.querySelector('.step-num');\r\n                if (n < step && numEl) numEl.innerHTML = '<i class=\"bi bi-check-lg\"></i>';\r\n                else if (numEl) numEl.textContent = n;\r\n            });\r\n        }\r\n\r\n        function updateGradeStats(students) {\r\n            const total = students.length;\r\n            const captured = students.filter(s => s.score !== null && s.score !== undefined && s.score !== '').length;\r\n            const pending = total - captured;\r\n            const noDocs = students.filter(s => !s.has_document).length;\r\n            const pct = total > 0 ? Math.round((captured / total) * 100) : 0;\r\n            document.getElementById('gsTotal').textContent = total;\r\n            document.getElementById('gsCaptured').textContent = captured;\r\n            document.getElementById('gsPending').textContent = pending;\r\n            document.getElementById('gsNoDocs').textContent = noDocs;\r\n            document.getElementById('gsProgressBar').style.width = pct + '%';\r\n            // Advance stepper based on state\r\n            if (total === 0) { updateStepper(2); return; }\r\n            if (pending === 0 && noDocs === 0) updateStepper(4);\r\n            else if (pending === 0) updateStepper(3);\r\n            else updateStepper(2);\r\n        }\r\n\r\n        async function saveAllGrades() {\r\n            const rows = document.querySelectorAll('#gradingTableBody tr');\r\n            let saved = 0, errors = 0;\r\n            const promises = [];\r\n            rows.forEach(tr => {\r\n                const id = tr.id?.replace('row_grade_','');\r\n                if (!id) return;\r\n                const input = document.getElementById(`score_${id}`);\r\n                if (!input || input.disabled || input.value === '') return;\r\n                const score = parseFloat(input.value);\r\n                if (isNaN(score) || score < 0 || score > 10) { errors++; return; }\r\n                const token = localStorage.getItem('token');\r\n                promises.push(\r\n                    fetch(`http://localhost:8000/teacher/grades/${id}`, {\r\n                        method: 'PUT',\r\n                        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },\r\n                        body: JSON.stringify({ score })\r\n                    }).then(r => r.ok ? saved++ : errors++).catch(() => errors++)\r\n                );\r\n            });\r\n            if (!promises.length) { showToast('No hay calificaciones nuevas para guardar', 'warning'); return; }\r\n            document.getElementById('btnSaveAll').disabled = true;\r\n            document.getElementById('btnSaveAll').innerHTML = '<i class=\"bi bi-hourglass-split me-2\"></i>Guardando...';\r\n            await Promise.all(promises);\r\n            document.getElementById('btnSaveAll').disabled = false;\r\n            document.getElementById('btnSaveAll').innerHTML = '<i class=\"bi bi-floppy-fill me-2\"></i>Guardar Todo';\r\n            if (errors) showToast(`${saved} guardadas · ${errors} con error`, 'warning');\r\n            else showToast(`✓ ${saved} calificaciones guardadas correctamente`);\r\n            loadStudentsForSubject();\r\n        }\r\n\r\n        let _currentGradeStudents = [];\r\n        let _currentGradeGroupTab = '';\r\n\r\n        function startGradeCapture(assignmentId) {\r\n            switchView('view-calificaciones');\r\n            const select = document.getElementById('selectSubjectForGrades');\r\n            if (select) {\r\n                select.value = assignmentId;\r\n                loadStudentsForSubject();\r\n            }\r\n        }\r\n\r\n        function renderGradeGroupTabs(students) {\r\n            const container = document.getElementById('gradingGroupTabs');\r\n            if (!container) return;\r\n\r\n            const groups = [...new Set((students || []).map(student => student.group_name || 'Sin grupo'))];\r\n            if (!groups.length) {\r\n                _currentGradeGroupTab = '';\r\n                container.innerHTML = '';\r\n                return;\r\n            }\r\n\r\n            if (!groups.includes(_currentGradeGroupTab)) {\r\n                _currentGradeGroupTab = groups[0];\r\n            }\r\n\r\n            container.innerHTML = groups.map(groupName => {\r\n                const count = students.filter(student => (student.group_name || 'Sin grupo') === groupName).length;\r\n                const activeClass = groupName === _currentGradeGroupTab\r\n                    ? 'btn-primary text-white'\r\n                    : 'btn-light text-primary border';\r\n                return `\r\n                    <button type=\"button\" class=\"btn btn-sm rounded-pill ${activeClass}\" onclick=\"selectGradeGroupTab('${String(groupName).replace(/'/g, \"\\\\'\")}')\">\r\n                        Grupo ${groupName} <span class=\"ms-1 badge bg-white text-primary\">${count}</span>\r\n                    </button>\r\n                `;\r\n            }).join('');\r\n        }\r\n\r\n        function selectGradeGroupTab(groupName) {\r\n            _currentGradeGroupTab = groupName;\r\n            renderGradeGroupTabs(_currentGradeStudents);\r\n            renderStudentsForActiveGradeGroup();\r\n        }\r\n\r\n        function applyScoreColor(input) {\r\n            const v = parseFloat(input.value);\r\n            input.classList.remove('score-pass','score-fail','score-neutral');\r\n            if (input.value === '') return;\r\n            if (v >= 6) input.classList.add('score-pass');\r\n            else if (v < 6 && v >= 0) input.classList.add('score-fail');\r\n            else input.classList.add('score-neutral');\r\n        }\r\n\r\n        function renderStudentsForActiveGradeGroup() {\r\n            const tbody = document.getElementById('gradingTableBody');\r\n            if (!tbody) return;\r\n\r\n            const selectedGroup = _currentGradeGroupTab || 'Sin grupo';\r\n            const students = (_currentGradeStudents || []).filter(student => (student.group_name || 'Sin grupo') === selectedGroup);\r\n\r\n            tbody.innerHTML = '';\r\n\r\n            if (!students.length) {\r\n                tbody.innerHTML = '<tr><td colspan=\"6\" class=\"text-center py-4 text-muted\">No hay alumnos en este grupo.</td></tr>';\r\n                return;\r\n            }\r\n\r\n            students.forEach((student) => {\r\n                const attemptBadge = student.attempt_type === 'Extemporaneo'\r\n                    ? '<span class=\"badge bg-warning text-dark ms-1\">Extemporáneo</span>'\r\n                    : student.attempt_type === 'Recursa'\r\n                        ? '<span class=\"badge bg-info text-dark ms-1\">Recursa</span>'\r\n                        : '';\r\n                const canAddExtemporaneo = student.status === 'Reprobada' && (student.attempt_type === 'Regular' || student.attempt_type === 'Recursa');\r\n                const isLocked = Boolean(student.teacher_locked);\r\n                const hasDoc = Boolean(student.has_document);\r\n                const docBadge = hasDoc\r\n                    ? `<button type=\"button\" class=\"btn btn-sm btn-success-subtle border border-success-subtle rounded-pill d-flex align-items-center gap-1\" onclick=\"viewGradeDocument(${student.grade_id})\" title=\"Ver comprobante subido\">\r\n                         <i class=\"bi bi-check-circle-fill text-success\"></i><span class=\"small text-success\">${student.document_filename || 'Ver'}</span>\r\n                       </button>`\r\n                    : `<button type=\"button\" class=\"btn btn-sm btn-light border rounded-pill d-flex align-items-center gap-1 text-secondary\" onclick=\"triggerDocUpload(${student.grade_id})\" title=\"Subir comprobante físico\">\r\n                         <i class=\"bi bi-camera\"></i><span class=\"small\">Adjuntar</span>\r\n                       </button>`;\r\n                const scoreVal = student.score !== null && student.score !== undefined ? student.score : '';\r\n                const scoreClass = scoreVal === '' ? '' : parseFloat(scoreVal) >= 6 ? 'score-pass' : 'score-fail';\r\n\r\n                const tr = document.createElement('tr');\r\n                tr.id = `row_grade_${student.grade_id}`;\r\n                tr.innerHTML = `\r\n                    <td><span class=\"badge bg-light text-dark border\">${student.username}</span></td>\r\n                    <td class=\"fw-bold\">${student.full_name || 'Sin nombre'}${attemptBadge}</td>\r\n                    <td class=\"grade-input-cell\">\r\n                        <input type=\"number\" class=\"${scoreClass}\"\r\n                            id=\"score_${student.grade_id}\"\r\n                            value=\"${scoreVal}\"\r\n                            min=\"0\" max=\"10\" step=\"0.1\" placeholder=\"—\" ${isLocked ? 'disabled' : ''}>\r\n                    </td>\r\n                    <td>\r\n                        <span class=\"badge ${student.status === 'Aprobada' ? 'bg-success' : student.status === 'Reprobada' ? 'bg-danger' : 'bg-secondary'}\" id=\"status_${student.grade_id}\">\r\n                            ${student.status}\r\n                        </span>\r\n                        ${isLocked ? '<span class=\"badge bg-dark ms-1\"><i class=\"bi bi-lock-fill\"></i></span>' : ''}\r\n                    </td>\r\n                    <td id=\"docCell_${student.grade_id}\">${docBadge}</td>\r\n                    <td class=\"d-flex gap-1 flex-wrap\">\r\n                        <button type=\"button\" class=\"btn btn-sm btn-primary rounded-pill\" onclick=\"saveGrade(${student.grade_id})\" ${isLocked ? 'disabled' : ''}>\r\n                            <i class=\"bi bi-floppy-fill me-1\"></i>Guardar\r\n                        </button>\r\n                        ${canAddExtemporaneo ? `<button type=\"button\" class=\"btn btn-sm btn-outline-warning rounded-pill\" onclick=\"addExtemporaneo(${document.getElementById('selectSubjectForGrades').value}, ${student.student_id})\" title=\"Extemporáneo\"><i class=\"bi bi-pencil-square\"></i></button>` : ''}\r\n                    </td>\r\n                `;\r\n                tbody.appendChild(tr);\r\n\r\n                const fileInput = document.createElement('input');\r\n                fileInput.type = 'file';\r\n                fileInput.accept = 'image/jpeg,image/png,image/webp,application/pdf';\r\n                fileInput.style.display = 'none';\r\n                fileInput.id = `fileInput_${student.grade_id}`;\r\n                fileInput.addEventListener('change', () => uploadGradeDocument(student.grade_id));\r\n                tr.appendChild(fileInput);\r\n                // Color reactivo al escribir\r\n                const inp = document.getElementById(`score_${student.grade_id}`);\r\n                if (inp) inp.addEventListener('input', () => applyScoreColor(inp));\r\n            });\r\n        }\r\n\r\n        async function loadStudentsForSubject() {\r\n            const assignmentId = document.getElementById('selectSubjectForGrades').value;\r\n            const gradingArea = document.getElementById('gradingArea');\r\n            const placeholder = document.getElementById('gradingPlaceholder');\r\n            const tbody = document.getElementById('gradingTableBody');\r\n            const printBtn = document.getElementById('btnPrintFormat');\r\n            const saveAllBtn = document.getElementById('btnSaveAll');\r\n            const tabs = document.getElementById('gradingGroupTabs');\r\n            const statsPanel = document.getElementById('gradeStatsPanel');\r\n            const pickerPanel = document.getElementById('subjectPickerPanel');\r\n\r\n            if (!assignmentId) {\r\n                gradingArea.style.display = 'none';\r\n                placeholder.style.display = 'block';\r\n                if (pickerPanel) pickerPanel.style.display = '';\r\n                if (statsPanel) statsPanel.style.display = 'none';\r\n                if (printBtn) printBtn.style.display = 'none';\r\n                if (saveAllBtn) saveAllBtn.style.display = 'none';\r\n                document.getElementById('gradeSubjectMeta').textContent = '';\r\n                _currentGradeStudents = [];\r\n                _currentGradeGroupTab = '';\r\n                if (tabs) tabs.innerHTML = '';\r\n                if (tbody) tbody.innerHTML = '';\r\n                updateStepper(1);\r\n                renderTeacherWorkQueue();\r\n                return;\r\n            }\r\n\r\n            const subjectName = document.getElementById('selectSubjectForGrades').selectedOptions[0]?.text || '';\r\n            const token = localStorage.getItem('token');\r\n            try {\r\n                const response = await fetch(`http://localhost:8000/teacher/students/${assignmentId}`, {\r\n                    headers: { 'Authorization': `Bearer ${token}` }\r\n                });\r\n                if (!response.ok) throw new Error('Error al cargar alumnos');\r\n\r\n                const students = await response.json();\r\n                _currentGradeStudents = students;\r\n                document.getElementById('teacherStudentsCount').textContent = students.length;\r\n                const groupsCount = new Set(students.map(s => s.group_name || 'Sin grupo')).size;\r\n                document.getElementById('gradeSubjectMeta').textContent =\r\n                    `${students.length} alumnos · ${groupsCount} grupo(s) · ${students.filter(s => s.status === 'Aprobada').length} aprobados · ${students.filter(s => s.status === 'Reprobada').length} reprobados`;\r\n\r\n                gradingArea.style.display = 'block';\r\n                placeholder.style.display = 'none';\r\n                if (pickerPanel) pickerPanel.style.display = 'none';\r\n                if (statsPanel) { statsPanel.style.display = ''; updateGradeStats(students); }\r\n                if (printBtn) printBtn.style.display = '';\r\n                if (saveAllBtn) saveAllBtn.style.display = '';\r\n                const selText = document.getElementById('selectSubjectForGrades').selectedOptions[0]?.text || '';\r\n                const titleEl = document.getElementById('gradeSubjectTitle');\r\n                if (titleEl) titleEl.textContent = selText;\r\n                tbody.innerHTML = '';\r\n\r\n                if (students.length === 0) {\r\n                    if (tabs) tabs.innerHTML = '';\r\n                    tbody.innerHTML = '<tr><td colspan=\"6\" class=\"text-center py-4 text-muted\">No hay alumnos inscritos en esta materia.</td></tr>';\r\n                    renderTeacherWorkQueue();\r\n                    return;\r\n                }\r\n\r\n                renderGradeGroupTabs(students);\r\n                renderStudentsForActiveGradeGroup();\r\n                renderTeacherWorkQueue();\r\n\r\n            } catch (error) {\r\n                console.error('Error:', error);\r\n                showToast('Error al cargar los alumnos de la materia', 'danger');\r\n                renderTeacherWorkQueue();\r\n            }\r\n        }\r\n\r\n        async function saveGrade(gradeId) {\r\n            const scoreInput = document.getElementById(`score_${gradeId}`).value;\r\n            if (scoreInput === '') { showToast('Ingresa una calificación (0-10)', 'warning'); return; }\r\n            const score = parseFloat(scoreInput);\r\n            if (isNaN(score) || score < 0 || score > 10) { showToast('La calificación debe ser entre 0 y 10', 'danger'); return; }\r\n            const token = localStorage.getItem('token');\r\n            try {\r\n                const response = await fetch(`http://localhost:8000/teacher/grades/${gradeId}`, {\r\n                    method: 'PUT',\r\n                    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },\r\n                    body: JSON.stringify({ score })\r\n                });\r\n                if (response.ok) {\r\n                    const updated = await response.json();\r\n                    const badge = document.getElementById(`status_${gradeId}`);\r\n                    if (badge) {\r\n                        badge.textContent = updated.status;\r\n                        badge.className = `badge ${updated.status === 'Aprobada' ? 'bg-success' : 'bg-danger'}`;\r\n                    }\r\n                    document.getElementById(`score_${gradeId}`).disabled = true;\r\n                    showToast(`Calificación ${score} guardada · ${updated.status}`);\r\n                    loadTeacherNotifications(false);\r\n                    loadStudentsForSubject();\r\n                } else {\r\n                    const err = await response.json().catch(() => ({}));\r\n                    showToast(err.detail || 'Error al guardar calificación', 'danger');\r\n                }\r\n            } catch { showToast('Error de conexión', 'danger'); }\r\n        }\r\n\r\n        function triggerDocUpload(gradeId) {\r\n            document.getElementById(`fileInput_${gradeId}`)?.click();\r\n        }\r\n\r\n        async function uploadGradeDocument(gradeId) {\r\n            const fileInput = document.getElementById(`fileInput_${gradeId}`);\r\n            if (!fileInput?.files?.length) return;\r\n            const file = fileInput.files[0];\r\n            const token = localStorage.getItem('token');\r\n            const cell = document.getElementById(`docCell_${gradeId}`);\r\n            if (cell) cell.innerHTML = '<span class=\"small text-muted\"><i class=\"bi bi-hourglass-split me-1\"></i>Subiendo...</span>';\r\n            try {\r\n                const form = new FormData();\r\n                form.append('file', file);\r\n                const res = await fetch(`http://localhost:8000/teacher/grades/${gradeId}/document`, {\r\n                    method: 'POST',\r\n                    headers: { 'Authorization': `Bearer ${token}` },\r\n                    body: form,\r\n                });\r\n                if (!res.ok) {\r\n                    const err = await res.json().catch(() => ({}));\r\n                    showToast(err.detail || 'Error al subir comprobante', 'danger');\r\n                    if (cell) cell.innerHTML = `<button type=\"button\" class=\"btn btn-sm btn-light border rounded-pill d-flex align-items-center gap-1 text-secondary\" onclick=\"triggerDocUpload(${gradeId})\"><i class=\"bi bi-camera\"></i><span class=\"small\">Reintentar</span></button>`;\r\n                    return;\r\n                }\r\n                const data = await res.json();\r\n                showToast('Comprobante subido correctamente', 'success');\r\n                if (cell) cell.innerHTML = `<button type=\"button\" class=\"btn btn-sm btn-success-subtle border border-success-subtle rounded-pill d-flex align-items-center gap-1\" onclick=\"viewGradeDocument(${gradeId})\"><i class=\"bi bi-check-circle-fill text-success\"></i><span class=\"small text-success\">${data.filename}</span></button>`;\r\n            } catch { showToast('Error de conexión al subir comprobante', 'danger'); }\r\n        }\r\n\r\n        function viewGradeDocument(gradeId) {\r\n            const token = localStorage.getItem('token');\r\n            window.open(`http://localhost:8000/teacher/grades/${gradeId}/document?token=${token}`, '_blank');\r\n        }\r\n\r\n        function printGradeFormat() {\r\n            const select = document.getElementById('selectSubjectForGrades');\r\n            const subjectName = select.selectedOptions[0]?.text || 'Materia';\r\n            const students = _currentGradeStudents;\r\n            if (!students.length) { showToast('No hay alumnos para imprimir', 'warning'); return; }\r\n\r\n            const now = new Date();\r\n            const dateStr = now.toLocaleDateString('es-MX', { day:'2-digit', month:'long', year:'numeric' });\r\n            const teacherName = document.getElementById('teacherName')?.textContent || 'Docente';\r\n\r\n            const approved = students.filter(s => s.status === 'Aprobada').length;\r\n            const failed = students.filter(s => s.status === 'Reprobada').length;\r\n            const scores = students.map(s => s.score).filter(s => s !== null && s !== undefined);\r\n            const avg = scores.length ? (scores.reduce((a,b) => a+b, 0) / scores.length).toFixed(1) : '-';\r\n\r\n            const rows = students.map((s, i) => {\r\n                const score = s.score !== null && s.score !== undefined ? Number(s.score).toFixed(1) : '—';\r\n                const statusClass = s.status === 'Aprobada' ? 'color:#166534' : s.status === 'Reprobada' ? 'color:#991b1b' : 'color:#555';\r\n                const docCheck = s.has_document ? '✓' : '';\r\n                return `<tr>\r\n                    <td style=\"text-align:center\">${i + 1}</td>\r\n                    <td style=\"text-align:center\">${s.username}</td>\r\n                    <td>${s.full_name || '-'}</td>\r\n                    <td style=\"text-align:center;font-weight:700;font-size:1.05rem\">${score}</td>\r\n                    <td style=\"text-align:center;${statusClass};font-weight:600\">${s.status}</td>\r\n                    <td style=\"text-align:center;color:#16a34a\">${docCheck}</td>\r\n                    <td style=\"border-bottom:1px solid #333;height:28px\"></td>\r\n                </tr>`;\r\n            }).join('');\r\n\r\n            const html = `<!DOCTYPE html><html lang=\"es\"><head><meta charset=\"UTF-8\">\r\n            <title>Formato de Calificaciones — ${subjectName}</title>\r\n            <style>\r\n                @page { size: letter portrait; margin: 18mm 20mm 18mm 20mm; }\r\n                * { box-sizing: border-box; }\r\n                body { font-family: 'Arial', sans-serif; font-size: 10pt; color: #111; margin: 0; }\r\n                .header { border-bottom: 3px solid #1141b8; padding-bottom: 10px; margin-bottom: 14px; display: flex; align-items: center; gap: 16px; }\r\n                .header-logo { width: 54px; height: 54px; background: #1141b8; border-radius: 10px; display: flex; align-items: center; justify-content: center; color: white; font-weight: 900; font-size: 22px; flex-shrink: 0; }\r\n                .header-info h1 { margin: 0 0 2px; font-size: 13pt; color: #0b2673; font-weight: 900; }\r\n                .header-info p { margin: 0; font-size: 8pt; color: #555; }\r\n                .meta-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px 20px; margin-bottom: 14px; background: #f0f5ff; border-radius: 8px; padding: 10px 14px; border: 1px solid #c7d7f5; }\r\n                .meta-item { font-size: 9pt; }\r\n                .meta-item .label { color: #555; font-size: 8pt; font-weight: 700; text-transform: uppercase; letter-spacing: .04em; }\r\n                .meta-item .val { font-weight: 700; color: #0b2673; }\r\n                h2.section-title { font-size: 10pt; font-weight: 800; color: #1141b8; margin: 0 0 8px; text-transform: uppercase; letter-spacing: .06em; }\r\n                table { width: 100%; border-collapse: collapse; margin-bottom: 18px; }\r\n                thead th { background: #1141b8; color: #fff; font-size: 8.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: .05em; padding: 6px 8px; }\r\n                tbody td { padding: 5px 8px; border-bottom: 1px solid #e5eaf5; font-size: 9.5pt; }\r\n                tbody tr:nth-child(even) td { background: #f8faff; }\r\n                .stats-row { display: flex; gap: 20px; margin-bottom: 18px; }\r\n                .stat-box { flex: 1; border: 1px solid #c7d7f5; border-radius: 8px; padding: 8px 12px; text-align: center; }\r\n                .stat-box .num { font-size: 18pt; font-weight: 900; color: #1141b8; }\r\n                .stat-box .lbl { font-size: 8pt; color: #555; text-transform: uppercase; letter-spacing: .04em; }\r\n                .signatures { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 30px; margin-top: 24px; }\r\n                .sig-box { text-align: center; }\r\n                .sig-line { border-top: 1.5px solid #111; margin-bottom: 4px; padding-top: 4px; font-size: 8pt; font-weight: 700; }\r\n                .sig-sub { font-size: 7.5pt; color: #555; }\r\n                .footer { margin-top: 20px; border-top: 1px solid #c7d7f5; padding-top: 8px; font-size: 7.5pt; color: #888; display: flex; justify-content: space-between; }\r\n                @media print { .no-print { display: none !important; } }\r\n            </style><link rel=\"preload\" href=\"style.min.css\" as=\"style\">\r\n    <link rel=\"preload\" href=\"assets/js/script.min.js\" as=\"script\">\r\n</head><body>\r\n\r\n            <div class=\"no-print\" style=\"padding:12px;background:#1141b8;color:white;text-align:center;cursor:pointer;font-weight:700\" onclick=\"window.print()\">\r\n                🖨️ Haz clic aquí para imprimir o guardar como PDF\r\n            </div>\r\n\r\n            <div class=\"header\">\r\n                <div class=\"header-logo\">U</div>\r\n                <div class=\"header-info\">\r\n                    <h1>Universidad Unives</h1>\r\n                    <p>Sistema de Control Escolar · Formato Oficial de Calificaciones</p>\r\n                    <p>Documento generado el ${dateStr}</p>\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\"meta-grid\">\r\n                <div class=\"meta-item\"><div class=\"label\">Materia</div><div class=\"val\">${subjectName}</div></div>\r\n                <div class=\"meta-item\"><div class=\"label\">Docente</div><div class=\"val\">${teacherName}</div></div>\r\n                <div class=\"meta-item\"><div class=\"label\">Fecha de captura</div><div class=\"val\">${dateStr}</div></div>\r\n                <div class=\"meta-item\"><div class=\"label\">Total de alumnos</div><div class=\"val\">${students.length}</div></div>\r\n            </div>\r\n\r\n            <h2 class=\"section-title\">Resumen de Resultados</h2>\r\n            <div class=\"stats-row\">\r\n                <div class=\"stat-box\"><div class=\"num\">${students.length}</div><div class=\"lbl\">Total</div></div>\r\n                <div class=\"stat-box\"><div class=\"num\" style=\"color:#166534\">${approved}</div><div class=\"lbl\">Aprobados</div></div>\r\n                <div class=\"stat-box\"><div class=\"num\" style=\"color:#991b1b\">${failed}</div><div class=\"lbl\">Reprobados</div></div>\r\n                <div class=\"stat-box\"><div class=\"num\" style=\"color:#1141b8\">${avg}</div><div class=\"lbl\">Promedio</div></div>\r\n            </div>\r\n\r\n            <h2 class=\"section-title\">Lista de Calificaciones</h2>\r\n            <table>\r\n                <thead><tr>\r\n                    <th style=\"width:30px\">#</th>\r\n                    <th style=\"width:80px\">Matrícula</th>\r\n                    <th>Nombre del Alumno</th>\r\n                    <th style=\"width:60px\">Calif.</th>\r\n                    <th style=\"width:80px\">Estatus</th>\r\n                    <th style=\"width:40px\">Doc.</th>\r\n                    <th style=\"width:110px\">Firma del alumno</th>\r\n                </tr></thead>\r\n                <tbody>${rows}</tbody>\r\n            </table>\r\n\r\n            <div class=\"signatures\">\r\n                <div class=\"sig-box\">\r\n                    <div style=\"height:50px\"></div>\r\n                    <div class=\"sig-line\">FIRMA DEL DOCENTE</div>\r\n                    <div class=\"sig-sub\">${teacherName}</div>\r\n                </div>\r\n                <div class=\"sig-box\">\r\n                    <div style=\"height:50px\"></div>\r\n                    <div class=\"sig-line\">FIRMA DEL DIRECTOR</div>\r\n                    <div class=\"sig-sub\">Director Académico</div>\r\n                </div>\r\n                <div class=\"sig-box\">\r\n                    <div style=\"height:50px\"></div>\r\n                    <div class=\"sig-line\">SELLO INSTITUCIONAL</div>\r\n                    <div class=\"sig-sub\">Universidad Unives</div>\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\"footer\">\r\n                <span>Unives · Control Escolar · Documento oficial</span>\r\n                <span>Generado: ${dateStr} · ${subjectName}</span>\r\n            </div>\r\n            ";